  useEffect(() => {
    const timerStates = ["shoot","save_dive","shoot_x","shoot_y"];
    if(timerStates.includes(kickState) && !kickCharging && !matchIntro) {
      setActionTimer(3);
      if(actionTimerRef.current) clearInterval(actionTimerRef.current);
      actionTimerRef.current = setInterval(()=>{
        setActionTimer(p=>{
          if(p<=1) {
            clearInterval(actionTimerRef.current); actionTimerRef.current=null;
            if(kickState==="shoot") { const rz=Math.floor(Math.random()*6); kickSelectZone(rz); playFx("error"); setCommentary("Too slow! Auto-kick! 🐌"); }
            else if(kickState==="save_dive") { const rz=Math.floor(Math.random()*6); kickDive(rz); playFx("error"); setCommentary("Too slow! Random dive! 🐌"); }
            else if(kickState==="shoot_x") { fk2LockX(20+Math.floor(Math.random()*60)); playFx("error"); setCommentary("Too slow! Random X aim! 🐌"); }
            else if(kickState==="shoot_y") { fk2LockY(20+Math.floor(Math.random()*60)); playFx("error"); setCommentary("Too slow! Random Y aim! 🐌"); }
            return 0;
          }
          return p-1;
        });
      },1000);
    } else {
      // Clear timer when charging starts or state changes to non-timer state
      if(actionTimerRef.current){clearInterval(actionTimerRef.current);actionTimerRef.current=null;}
      if(kickCharging) setActionTimer(0);
    }
    return()=>{if(actionTimerRef.current){clearInterval(actionTimerRef.current);actionTimerRef.current=null;}};
  }, [kickState, kickCharging, matchIntro]);

  // ── THREE.JS 3D SCENE FOR FK3 — FULL SCREEN IMMERSIVE ──
  useEffect(() => {
    const isFK3Now = isFK3Mode || isFK3Ref.current;
    const isActive3D = ["shoot_x","shoot_y","flight","shoot_result","save_ready","save_countdown","save_dive","save_result"].includes(kickState);
    if(!isFK3Now || !isActive3D || typeof THREE === "undefined") {
      if(threeSceneRef.current) {
        const s = threeSceneRef.current;
        if(s.animId) cancelAnimationFrame(s.animId);
        if(s.renderer) { s.renderer.dispose(); s.renderer.domElement.remove(); }
        threeSceneRef.current = null;
      }
      return;
    }
    if(threeSceneRef.current) return;
    const container = threeCanvasRef.current;
    if(!container) return;

    const W = container.clientWidth || 430;
    const H = container.clientHeight || 932;
    const scene = new THREE.Scene();
    scene.fog = new THREE.Fog(0x0a1628, 30, 120);
    scene.background = new THREE.Color(0x0a1628);

    const camera = new THREE.PerspectiveCamera(60, W/H, 0.1, 1000);
    camera.position.set(0, 1.5, 12);
    camera.lookAt(0, 1.2, 0);

    const renderer = new THREE.WebGLRenderer({ antialias:true, alpha:false });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    container.innerHTML = "";
    container.appendChild(renderer.domElement);
    renderer.domElement.style.display = "block";

    // ── GROUND — Large grass field with stripe texture ──
    const groundGeo = new THREE.PlaneGeometry(80, 60);
    const groundMat = new THREE.MeshStandardMaterial({ color:0x1a6b2a, roughness:0.85, metalness:0.0 });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI/2;
    ground.receiveShadow = true;
    scene.add(ground);
    // Grass stripes (alternating lighter/darker bands)
    for(let i = -6; i <= 6; i++) {
      const stripeGeo = new THREE.PlaneGeometry(80, 2.5);
      const stripeMat = new THREE.MeshStandardMaterial({ color: i%2===0 ? 0x1e7a32 : 0x186828, roughness:0.85 });
      const stripe = new THREE.Mesh(stripeGeo, stripeMat);
      stripe.rotation.x = -Math.PI/2;
      stripe.position.set(0, 0.005, i * 2.5);
      scene.add(stripe);
    }
    // Penalty area lines
    const lineMat = new THREE.MeshBasicMaterial({ color:0xffffff, transparent:true, opacity:0.35 });
    const penAreaW = 16.5, penAreaD = 5;
    const pLineGeos = [
      { w:0.08, h:penAreaD, x:0, z:penAreaD/2 },
      { w:penAreaW, h:0.08, x:0, z:penAreaD },
      { w:0.08, h:penAreaD, x:-penAreaW/2, z:penAreaD/2 },
      { w:0.08, h:penAreaD, x:penAreaW/2, z:penAreaD/2 },
    ];
    pLineGeos.forEach(l => {
      const g = new THREE.PlaneGeometry(l.w, l.h);
      const m = new THREE.Mesh(g, lineMat);
      m.rotation.x = -Math.PI/2;
      m.position.set(l.x, 0.01, l.z);
      scene.add(m);
    });
    // Penalty spot
    const penSpotGeo = new THREE.CircleGeometry(0.12, 12);
    const penSpot = new THREE.Mesh(penSpotGeo, lineMat.clone());
    penSpot.rotation.x = -Math.PI/2;
    penSpot.position.set(0, 0.01, 11);
    scene.add(penSpot);

    // ── GOAL — Thick realistic posts + crossbar ──
    const gW = 7.32, gH = 2.44, postR = 0.08;
    const postMat = new THREE.MeshStandardMaterial({ color:0xffffff, metalness:0.7, roughness:0.25 });
    const lPost = new THREE.Mesh(new THREE.CylinderGeometry(postR, postR, gH, 12), postMat);
    lPost.position.set(-gW/2, gH/2, 0);
    lPost.castShadow = true;
    scene.add(lPost);
    const rPost = new THREE.Mesh(new THREE.CylinderGeometry(postR, postR, gH, 12), postMat);
    rPost.position.set(gW/2, gH/2, 0);
    rPost.castShadow = true;
    scene.add(rPost);
    const crossbar = new THREE.Mesh(new THREE.CylinderGeometry(postR, postR, gW+postR*2, 12), postMat);
    crossbar.rotation.z = Math.PI/2;
    crossbar.position.set(0, gH, 0);
    crossbar.castShadow = true;
    scene.add(crossbar);
    // Side support struts
    const strutMat = new THREE.MeshStandardMaterial({ color:0xdddddd, metalness:0.5, roughness:0.4 });
    [-1,1].forEach(side => {
      const strut = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 2.8, 6), strutMat);
      strut.position.set(side*gW/2, gH/2, -1);
      strut.rotation.x = 0.15;
      scene.add(strut);
    });

    // ── NET — Visible mesh on back and sides ──
    const netMat = new THREE.MeshBasicMaterial({ color:0xccddff, wireframe:true, transparent:true, opacity:0.18, side:THREE.DoubleSide });
    // Back net
    const netGeo = new THREE.PlaneGeometry(gW, gH, 20, 10);
    const net = new THREE.Mesh(netGeo, netMat);
    net.position.set(0, gH/2, -1.8);
    scene.add(net);
    // Bottom net
    const netBotGeo = new THREE.PlaneGeometry(gW, 1.8, 20, 4);
    const netBot = new THREE.Mesh(netBotGeo, netMat.clone());
    netBot.rotation.x = -Math.PI/2;
    netBot.position.set(0, 0.01, -0.9);
    scene.add(netBot);
    // Side nets
    [-1,1].forEach(side => {
      const sNetGeo = new THREE.PlaneGeometry(1.8, gH, 4, 10);
      const sNet = new THREE.Mesh(sNetGeo, netMat.clone());
      sNet.position.set(side*gW/2, gH/2, -0.9);
      sNet.rotation.y = side * Math.PI/2;
      scene.add(sNet);
    });
    // Top net
    const topNetGeo = new THREE.PlaneGeometry(gW, 1.8, 20, 4);
    const topNet = new THREE.Mesh(topNetGeo, netMat.clone());
    topNet.rotation.x = Math.PI/2;
    topNet.position.set(0, gH, -0.9);
    scene.add(topNet);

    // ── BALL — Realistic pentagon-panel pattern ──
    const ballGeo = new THREE.IcosahedronGeometry(0.22, 1);
    const ballMat = new THREE.MeshStandardMaterial({ color:0xffffff, roughness:0.25, metalness:0.05, flatShading:true });
    const ball = new THREE.Mesh(ballGeo, ballMat);
    ball.position.set(0, 0.22, 11);
    ball.castShadow = true;
    scene.add(ball);
    // Pentagon patch wireframe overlay
    const patchGeo = new THREE.IcosahedronGeometry(0.225, 1);
    const patchMat = new THREE.MeshBasicMaterial({ color:0x111111, wireframe:true, transparent:true, opacity:0.25 });
    const ballPatches = new THREE.Mesh(patchGeo, patchMat);
    ball.add(ballPatches);
    // Dark pentagon accent patches (alternating faces)
    const darkPatchGeo = new THREE.IcosahedronGeometry(0.218, 1);
    const darkPatchMat = new THREE.MeshStandardMaterial({ color:0x222222, roughness:0.4, metalness:0.1, flatShading:true, transparent:true, opacity:0.35 });
    const darkPatches = new THREE.Mesh(darkPatchGeo, darkPatchMat);
    ball.add(darkPatches);
    // Subtle glow ring around ball
    const ballGlowGeo = new THREE.RingGeometry(0.24, 0.30, 16);
    const ballGlowMat = new THREE.MeshBasicMaterial({ color:0xffffff, transparent:true, opacity:0.08, side:THREE.DoubleSide });
    const ballGlow = new THREE.Mesh(ballGlowGeo, ballGlowMat);
    ballGlow.rotation.x = -Math.PI/2;
    ballGlow.position.set(0, 0.01, 0);
    ball.add(ballGlow);

    // ── KEEPER — Bright neon-visible humanoid ──
    const keeperGroup = new THREE.Group();
    // Legs (dark shorts)
    const legGeo = new THREE.CylinderGeometry(0.09, 0.08, 0.9, 8);
    const legMat = new THREE.MeshStandardMaterial({ color:0x222222, roughness:0.6 });
    const lLeg = new THREE.Mesh(legGeo, legMat);
    lLeg.position.set(-0.13, 0.45, 0);
    keeperGroup.add(lLeg);
    const rLeg = new THREE.Mesh(legGeo, legMat);
    rLeg.position.set(0.13, 0.45, 0);
    keeperGroup.add(rLeg);
    // Boots (bright cleats)
    const bootGeo = new THREE.BoxGeometry(0.14, 0.1, 0.2);
    const bootMat = new THREE.MeshStandardMaterial({ color:0xff4400, emissive:0xff2200, emissiveIntensity:0.2, roughness:0.4 });
    const lBoot = new THREE.Mesh(bootGeo, bootMat);
    lBoot.position.set(-0.13, 0.02, 0.04);
    keeperGroup.add(lBoot);
    const rBoot = new THREE.Mesh(bootGeo, bootMat);
    rBoot.position.set(0.13, 0.02, 0.04);
    keeperGroup.add(rBoot);
    // Body (bright neon yellow keeper jersey)
    const bodyGeo = new THREE.CylinderGeometry(0.30, 0.24, 0.75, 10);
    const bodyMat = new THREE.MeshStandardMaterial({ color:0xffee00, emissive:0xffee00, emissiveIntensity:0.15, roughness:0.4 });
    const body = new THREE.Mesh(bodyGeo, bodyMat);
    body.position.y = 1.25;
    keeperGroup.add(body);
    // Jersey number (#1)
    const numGeo = new THREE.PlaneGeometry(0.2, 0.25);
    const numMat = new THREE.MeshBasicMaterial({ color:0x000000, transparent:true, opacity:0.5 });
    const num = new THREE.Mesh(numGeo, numMat);
    num.position.set(0, 1.3, 0.25);
    keeperGroup.add(num);
    // Head
    const headGeo = new THREE.SphereGeometry(0.19, 12, 12);
    const headMat = new THREE.MeshStandardMaterial({ color:0xffcc88, roughness:0.5 });
    const head = new THREE.Mesh(headGeo, headMat);
    head.position.y = 1.82;
    keeperGroup.add(head);
    // Cap
    const capGeo = new THREE.CylinderGeometry(0.22, 0.20, 0.08, 12);
    const capMat = new THREE.MeshStandardMaterial({ color:0xffee00, emissive:0xffee00, emissiveIntensity:0.1, roughness:0.5 });
    const cap = new THREE.Mesh(capGeo, capMat);
    cap.position.y = 1.95;
    keeperGroup.add(cap);
    // Arms (long sleeves matching jersey)
    const armGeo = new THREE.CylinderGeometry(0.07, 0.06, 0.7, 6);
    const armMat = new THREE.MeshStandardMaterial({ color:0xffee00, emissive:0xffee00, emissiveIntensity:0.1, roughness:0.5 });
    const lArm = new THREE.Mesh(armGeo, armMat);
    lArm.position.set(-0.40, 1.25, 0);
    lArm.rotation.z = Math.PI/6;
    keeperGroup.add(lArm);
    const rArm = new THREE.Mesh(armGeo, armMat);
    rArm.position.set(0.40, 1.25, 0);
    rArm.rotation.z = -Math.PI/6;
    keeperGroup.add(rArm);
    // Gloves (BIGGER, BRIGHT green with strong glow)
    const gloveGeo = new THREE.SphereGeometry(0.14, 10, 10);
    const gloveMat = new THREE.MeshStandardMaterial({ color:0x00ff66, emissive:0x00ff66, emissiveIntensity:0.6, roughness:0.2 });
    const lGlove = new THREE.Mesh(gloveGeo, gloveMat);
    lGlove.position.set(-0.70, 1.55, 0);
    keeperGroup.add(lGlove);
    const rGlove = new THREE.Mesh(gloveGeo, gloveMat);
    rGlove.position.set(0.70, 1.55, 0);
    keeperGroup.add(rGlove);
    keeperGroup.position.set(0, 0, 0.5);
    scene.add(keeperGroup);

    // ── KEEPER POV GLOVES (visible in save phase) ──
    const povGloveGroup = new THREE.Group();
    const povGloveMat = new THREE.MeshStandardMaterial({ color:0x00ff66, emissive:0x00ff44, emissiveIntensity:0.5, roughness:0.3 });
    const povLGlove = new THREE.Mesh(new THREE.BoxGeometry(0.5, 0.35, 0.15, 2, 2, 2), povGloveMat);
    povLGlove.position.set(-0.7, -0.6, -0.8);
    povLGlove.rotation.set(0.2, 0.3, -0.15);
    povGloveGroup.add(povLGlove);
    const povRGlove = new THREE.Mesh(new THREE.BoxGeometry(0.5, 0.35, 0.15, 2, 2, 2), povGloveMat.clone());
    povRGlove.position.set(0.7, -0.6, -0.8);
    povRGlove.rotation.set(0.2, -0.3, 0.15);
    povGloveGroup.add(povRGlove);
    // Wrist bands
    const wristMat = new THREE.MeshStandardMaterial({ color:0x00cc55, roughness:0.5 });
    const povLWrist = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.12, 0.08, 8), wristMat);
    povLWrist.position.set(-0.7, -0.4, -0.8);
    povGloveGroup.add(povLWrist);
    const povRWrist = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.12, 0.08, 8), wristMat.clone());
    povRWrist.position.set(0.7, -0.4, -0.8);
    povGloveGroup.add(povRWrist);
    povGloveGroup.visible = false;
    scene.add(povGloveGroup);

    // ── STADIUM — Background stands with crowd ──
    const standMat = new THREE.MeshStandardMaterial({ color:0x1a2540, roughness:0.9 });
    // Back stand (behind goal)
    const backStand = new THREE.Mesh(new THREE.BoxGeometry(50, 12, 3), standMat);
    backStand.position.set(0, 5, -12);
    scene.add(backStand);
    // Side stands
    [-1,1].forEach(side => {
      const sideStand = new THREE.Mesh(new THREE.BoxGeometry(3, 10, 40), standMat.clone());
      sideStand.position.set(side*22, 4, 5);
      scene.add(sideStand);
    });
    // Far stand (behind kicker)
    const farStand = new THREE.Mesh(new THREE.BoxGeometry(50, 8, 3), standMat.clone());
    farStand.position.set(0, 3, 25);
    scene.add(farStand);
    // Crowd dots on stands
    const crowdColors = [0xff4444, 0x4488ff, 0xffdd44, 0xff8844, 0x44ff88, 0xffffff, 0xff66aa];
    const crowdDots = [];
    for(let i = 0; i < 200; i++) {
      const cGeo = new THREE.SphereGeometry(0.15+Math.random()*0.1, 4, 4);
      const cMat = new THREE.MeshBasicMaterial({ color:crowdColors[Math.floor(Math.random()*crowdColors.length)] });
      const cDot = new THREE.Mesh(cGeo, cMat);
      const angle = Math.random()*Math.PI*2;
      const r = 15+Math.random()*10;
      cDot.position.set(
        Math.sin(angle)*r*(0.8+Math.random()*0.4),
        1+Math.random()*8,
        Math.cos(angle)*r*(0.3+Math.random()*0.5) - 5
      );
      scene.add(cDot);
      crowdDots.push(cDot);
    }
    // Stadium floodlight towers
    const towerMat = new THREE.MeshStandardMaterial({ color:0x445566, metalness:0.6, roughness:0.4 });
    [[-15,0],[-15,20],[15,0],[15,20]].forEach(([tx,tz]) => {
      const tower = new THREE.Mesh(new THREE.CylinderGeometry(0.15, 0.2, 18, 6), towerMat);
      tower.position.set(tx, 9, tz);
      scene.add(tower);
      const lampGeo = new THREE.BoxGeometry(1.5, 0.3, 0.5);
      const lampMat = new THREE.MeshBasicMaterial({ color:0xffffcc });
      const lamp = new THREE.Mesh(lampGeo, lampMat);
      lamp.position.set(tx, 18, tz);
      scene.add(lamp);
    });

    // ── AIM LINES ──
    const aimLineVGeo = new THREE.PlaneGeometry(0.05, gH);
    const aimLineVMat = new THREE.MeshBasicMaterial({ color:0x00e5ff, transparent:true, opacity:0.9, side:THREE.DoubleSide });
    const aimLineV = new THREE.Mesh(aimLineVGeo, aimLineVMat);
    aimLineV.position.set(0, gH/2, 0.05);
    aimLineV.visible = false;
    scene.add(aimLineV);
    const aimLineHGeo = new THREE.PlaneGeometry(gW, 0.05);
    const aimLineHMat = new THREE.MeshBasicMaterial({ color:0xfb923c, transparent:true, opacity:0.9, side:THREE.DoubleSide });
    const aimLineH = new THREE.Mesh(aimLineHGeo, aimLineHMat);
    aimLineH.position.set(0, gH/2, 0.05);
    aimLineH.visible = false;
    scene.add(aimLineH);
    const dotGeo = new THREE.SphereGeometry(0.1, 8, 8);
    const dotMat = new THREE.MeshBasicMaterial({ color:0xffffff });
    const dot = new THREE.Mesh(dotGeo, dotMat);
    dot.position.set(0, gH/2, 0.1);
    dot.visible = false;
    scene.add(dot);

    // ── LIGHTING — HemisphereLight + SpotLights ──
    const hemiLight = new THREE.HemisphereLight(0x88aaff, 0x224422, 0.6);
    scene.add(hemiLight);
    const spotLight1 = new THREE.SpotLight(0xffffff, 200, 60, Math.PI/4, 0.5, 1);
    spotLight1.position.set(-10, 20, 8);
    spotLight1.castShadow = true;
    spotLight1.shadow.mapSize.width = 512;
    spotLight1.shadow.mapSize.height = 512;
    scene.add(spotLight1);
    const spotLight2 = new THREE.SpotLight(0xffffff, 200, 60, Math.PI/4, 0.5, 1);
    spotLight2.position.set(10, 20, 8);
    spotLight2.castShadow = true;
    scene.add(spotLight2);
    const ambient = new THREE.AmbientLight(0x445566, 0.4);
    scene.add(ambient);
    // Colored accent lights
    const accentL = new THREE.PointLight(0x00ccff, 40, 40);
    accentL.position.set(-8, 8, 5);
    scene.add(accentL);
    const accentR = new THREE.PointLight(0xffaa00, 40, 40);
    accentR.position.set(8, 8, 5);
    scene.add(accentR);
    const rimLight = new THREE.PointLight(0xcc88ff, 25, 25);
    rimLight.position.set(0, 6, -6);
    scene.add(rimLight);

    const trailParticles = [];
    const resultParticles = [];

    const state = {
      scene, camera, renderer, ball, keeperGroup, net, povGloveGroup,
      aimLineV, aimLineH, dot, trailParticles, resultParticles, crowdDots,
      gW, gH, W, H, animId: null, startTime: Date.now(),
      ballStart: new THREE.Vector3(0, 0.22, 11),
      ballTarget: new THREE.Vector3(0, 1, -0.3),
      flightProgress: 0, flightDone: false,
      keeperDiveTarget: 0, keeperDiving: false,
      resultShown: false,
      cameraMode: "shoot", // "shoot" | "save"
      baseFOV: 60, targetFOV: 60,
      saveBallStart: new THREE.Vector3(0, 0.22, 20),
      saveBallTarget: new THREE.Vector3(0, 1.2, 0),
      saveBallProgress: 0, saveBallDone: false,
      saveDiveDir: 0,
      povGloveBaseL: new THREE.Vector3(-0.7, -0.6, -0.8),
      povGloveBaseR: new THREE.Vector3(0.7, -0.6, -0.8),
    };
    threeSceneRef.current = state;

    // Resize handler
    const onResize = () => {
      const cw = container.clientWidth || 430;
      const ch = container.clientHeight || 932;
      state.W = cw; state.H = ch;
      camera.aspect = cw/ch;
      camera.updateProjectionMatrix();
      renderer.setSize(cw, ch);
    };
    window.addEventListener("resize", onResize);

    const animate = () => {
      state.animId = requestAnimationFrame(animate);
      const t = (Date.now() - state.startTime) / 1000;

      // FOV lerp
      camera.fov += (state.targetFOV - camera.fov) * 0.05;
      camera.updateProjectionMatrix();

      if(state.cameraMode === "shoot") {
        // Subtle camera sway during aiming
        if(!state.flightProgress || state.flightProgress < 0.01) {
          camera.position.x += (Math.sin(t * 0.3) * 0.12 - camera.position.x) * 0.03;
          camera.position.y += (1.5 + Math.sin(t * 0.5) * 0.04 - camera.position.y) * 0.03;
        }
        // Keeper idle
        if(!state.keeperDiving) {
          keeperGroup.position.x = Math.sin(t * 1.5) * 0.3;
          keeperGroup.children.forEach((c, i) => {
            if(i === 2) c.rotation.z = Math.sin(t * 2) * 0.03;
          });
        }
      }

      // ── CROWD CHEERING ANIMATION — dots bob up and down ──
      crowdDots.forEach((dot, i) => {
        const freq = 1.5 + (i % 7) * 0.3;
        const amp = 0.15 + (i % 5) * 0.05;
        dot.position.y += Math.sin(t * freq + i * 0.7) * amp * 0.01;
        // Wave effect — crowd does the wave
        const wavePhase = (t * 0.8 + i * 0.05) % (Math.PI * 2);
        if(wavePhase < 0.5) dot.position.y += 0.03;
      });

      // ── BALL FLIGHT ANIMATION (runs per frame) ──
      if(state.cameraMode === "shoot" && state.flightActive && !state.flightDone) {
        state.flightProgress += 0.025;
        if(state.flightProgress >= 1) { state.flightProgress = 1; state.flightDone = true; }
        const p = state.flightProgress;
        const peakHeight = Math.max(state.ballTarget.y, state.gH * 0.7) + 2.0;
        const peakX = state.ballTarget.x * 0.5;
        const peakZ = state.ballStart.z * 0.4;
        const t1 = 1 - p;
        ball.position.x = t1*t1*state.ballStart.x + 2*t1*p*peakX + p*p*state.ballTarget.x;
        ball.position.y = t1*t1*state.ballStart.y + 2*t1*p*peakHeight + p*p*state.ballTarget.y;
        ball.position.z = t1*t1*state.ballStart.z + 2*t1*p*peakZ + p*p*state.ballTarget.z;
        ball.rotation.x += 0.35;
        ball.rotation.z += 0.12;
        // Camera follows
        const camZ = 12 - p * 8;
        const camX = ball.position.x * 0.25;
        const camY = 1.5 + (ball.position.y - 1.5) * 0.3;
        camera.position.x += (camX - camera.position.x) * 0.08;
        camera.position.y += (camY - camera.position.y) * 0.08;
        camera.position.z += (camZ - camera.position.z) * 0.08;
        camera.lookAt(ball.position.x*0.4, ball.position.y*0.5+0.8, Math.min(ball.position.z, 2));
        state.targetFOV = 60 - p * 22;
        // Vapor trail
        if(Math.random() < 0.6) {
          const tGeo = new THREE.SphereGeometry(0.07, 4, 4);
          const tMat = new THREE.MeshBasicMaterial({color:0xaaddff,transparent:true,opacity:0.5});
          const tMesh = new THREE.Mesh(tGeo, tMat);
          tMesh.position.copy(ball.position);
          tMesh.position.x += (Math.random()-0.5)*0.08;
          scene.add(tMesh);
          state.trailParticles.push({mesh:tMesh});
        }
        // Keeper dive
        if(p > 0.3 && !state.keeperDiving) { state.keeperDiving = true; state.keeperDiveTarget = state.ballTarget.x; }
        if(state.keeperDiving) {
          keeperGroup.position.x += (state.keeperDiveTarget * 0.85 - keeperGroup.position.x) * 0.06;
          const diveDir = state.keeperDiveTarget > 0 ? 1 : -1;
          keeperGroup.rotation.z += diveDir * 0.025;
          // Move arms toward ball
          if(keeperGroup.children[4]) keeperGroup.children[4].rotation.z = Math.PI/3 * diveDir;
          if(keeperGroup.children[5]) keeperGroup.children[5].rotation.z = -Math.PI/3 * diveDir;
        }
      }

      // ── MOVE POV GLOVES based on touch/mouse position ──
      if(state.cameraMode === "save" && state.povGloveGroup && state.povGloveGroup.visible) {
        const gx = (fk3GloveRef.current.x - 0.5) * 5.0; // map 0-1 to -2.5 to 2.5
        const gy = (fk3GloveRef.current.y - 0.5) * 3.0 - 1.5; // map 0-1 to -3 to 1.5
        state.povGloveGroup.position.x += (gx - state.povGloveGroup.position.x) * 0.15;
        state.povGloveGroup.position.y += (gy - state.povGloveGroup.position.y) * 0.15;
      }

      // ── SAVE BALL FLIGHT (keeper POV — ball flying toward you) ──
      if(state.cameraMode === "save" && state.saveBallActive && !state.saveBallDone) {
        state.saveBallProgress += 0.035;
        if(state.saveBallProgress >= 1) { state.saveBallProgress = 1; state.saveBallDone = true; }
        const p = state.saveBallProgress;
        const tX = state.saveBallTargetX || 0;
        const tY = state.saveBallTargetY || 1.0;
        ball.position.x = tX * p;
        ball.position.y = 0.22 + (tY - 0.22) * p + Math.sin(p * Math.PI) * 1.0;
        ball.position.z = 18 - p * 18.5;
        ball.rotation.x -= 0.4;
        ball.rotation.z += 0.15;
        const sc = 1 + p * 1.5;
        ball.scale.set(sc, sc, sc);

        // Auto-detect save when ball arrives close to camera
        if(p >= 0.9 && !state.saveChecked) {
          state.saveChecked = true;
          // Check distance between gloves and ball
          const glovePos = state.povGloveGroup.position;
          const ballPos = ball.position;
          const dist = Math.sqrt(Math.pow(glovePos.x - ballPos.x, 2) + Math.pow(glovePos.y - ballPos.y, 2));
          // Map to zone based on glove position for game logic
          const gx = fk3GloveRef.current.x;
          const gy = fk3GloveRef.current.y;
          const col = gx < 0.33 ? 0 : gx < 0.67 ? 1 : 2;
          const row = gy > 0.5 ? 0 : 1;
          const gloveZone = row * 3 + col;
          // Trigger the kickDive with the mapped zone
          if(typeof kickDive === "function") kickDive(gloveZone);
        }
      }

      // Crowd wave animation
      crowdDots.forEach((cd, i) => {
        cd.position.y += Math.sin(t*2 + i*0.3) * 0.003;
      });

      // Trail particles
      for(let i = state.trailParticles.length - 1; i >= 0; i--) {
        const p = state.trailParticles[i];
        p.mesh.material.opacity -= 0.015;
        p.mesh.scale.multiplyScalar(0.96);
        if(p.mesh.material.opacity <= 0) {
          scene.remove(p.mesh);
          p.mesh.geometry.dispose(); p.mesh.material.dispose();
          state.trailParticles.splice(i, 1);
        }
      }
      // Result particles
      for(let i = state.resultParticles.length - 1; i >= 0; i--) {
        const p = state.resultParticles[i];
        p.mesh.position.add(p.vel);
        p.vel.y -= 0.003;
        p.mesh.material.opacity -= 0.012;
        if(p.mesh.material.opacity <= 0) {
          scene.remove(p.mesh);
          p.mesh.geometry.dispose(); p.mesh.material.dispose();
          state.resultParticles.splice(i, 1);
        }
      }

      renderer.render(scene, camera);
    };
    animate();

    return () => {
      window.removeEventListener("resize", onResize);
      if(state.animId) cancelAnimationFrame(state.animId);
      if(state.renderer) { state.renderer.dispose(); state.renderer.domElement.remove(); }
      threeSceneRef.current = null;
    };
  }, [isFK3Mode, kickState]);

  // ── FK3 3D scene updates (aim lines, ball flight, keeper dive, SAVE POV) ──
  useEffect(() => {
    const s = threeSceneRef.current;
    if(!s) return;
    const isFK3Now = isFK3Mode || isFK3Ref.current;
    if(!isFK3Now) return;

    const gW = s.gW, gH = s.gH;

    // ── SHOOT PHASE: Aim lines ──
    if(kickState === "shoot_x") {
      s.cameraMode = "shoot";
      s.keeperGroup.visible = true;
      s.povGloveGroup.visible = false;
      s.targetFOV = 60;
      s.flightActive = false; s.flightDone = false; s.keeperDiving = false;
      s.saveBallActive = false; s.saveBallDone = false;
      s.ball.position.set(0, 0.22, 11); s.ball.scale.set(1,1,1);
      s.keeperGroup.position.set(0, 0, 0.5); s.keeperGroup.rotation.set(0,0,0);
      s.camera.position.set(0, 1.5, 12); s.camera.lookAt(0, 1.2, 0);
      s.aimLineV.visible = kickCharging && kickPower > 0;
      s.aimLineH.visible = false;
      s.dot.visible = false;
      if(kickCharging && kickPower > 0) {
        const xPos = (kickPower / 100 - 0.5) * gW;
        s.aimLineV.position.x = xPos;
        const isPerfect = kickPower >= kickSweetMin && kickPower <= kickSweetMax;
        const isOOB = kickPower < 10 || kickPower > 90;
        s.aimLineV.material.color.setHex(isOOB ? 0xff4444 : isPerfect ? 0x34d399 : 0x00e5ff);
      }
    } else if(kickState === "shoot_y") {
      s.cameraMode = "shoot";
      s.keeperGroup.visible = true;
      s.povGloveGroup.visible = false;
      s.targetFOV = 60;
      s.aimLineV.visible = true;
      const lockedX = (fk2X / 100 - 0.5) * gW;
      s.aimLineV.position.x = lockedX;
      s.aimLineV.material.color.setHex(0x34d399);
      s.aimLineV.material.opacity = 0.5;
      s.aimLineH.visible = kickCharging && kickPower > 0;
      s.dot.visible = kickCharging && kickPower > 0;
      if(kickCharging && kickPower > 0) {
        const yPos = (kickPower / 100) * gH;
        s.aimLineH.position.y = yPos;
        const isPerfect = kickPower >= kickSweetMin && kickPower <= kickSweetMax;
        const isOOB = kickPower > 95;
        s.aimLineH.material.color.setHex(isOOB ? 0xff4444 : isPerfect ? 0x34d399 : 0xfb923c);
        s.dot.position.set(lockedX, yPos, 0.1);
        s.dot.material.color.setHex(isPerfect ? 0x34d399 : 0xffffff);
      }
    } else if(kickState === "flight") {
      // ── BALL FLIGHT: Set flags for animation loop ──
      s.aimLineV.visible = false;
      s.aimLineH.visible = false;
      s.dot.visible = false;
      s.keeperGroup.visible = true;
      s.povGloveGroup.visible = false;
      s.cameraMode = "shoot";
      // Activate flight in animation loop (if not already)
      if(!s.flightActive) {
        s.flightActive = true;
        s.flightProgress = 0;
        s.flightDone = false;
        s.keeperDiving = false;
        // Set ball start + target from FK2 aim values
        const xPos = (fk2X / 100 - 0.5) * s.gW;
        const yPos = (fk2Y / 100) * s.gH;
        s.ballStart = { x: 0, y: 0.22, z: 11 };
        s.ballTarget = { x: xPos, y: Math.max(yPos, 0.3), z: 0.3 };
        s.ball.position.set(0, 0.22, 11);
        s.ball.visible = true;
      }
    } else if(kickState === "shoot_result") {
      s.aimLineV.visible = false;
      s.aimLineH.visible = false;
      s.dot.visible = false;
      s.keeperGroup.visible = true;
      s.povGloveGroup.visible = false;

      if(!s.resultShown && kickBallAnim) {
        s.resultShown = true;
        const isGoal = kickBallAnim.result === "goal";
        const isMiss = kickBallAnim.result === "miss";

        if(isGoal) {
          for(let i = 0; i < 30; i++) {
            const pGeo = new THREE.SphereGeometry(0.05+Math.random()*0.06, 4, 4);
            const pMat = new THREE.MeshBasicMaterial({ color:0x34d399, transparent:true, opacity:0.8 });
            const pMesh = new THREE.Mesh(pGeo, pMat);
            pMesh.position.copy(s.ball.position);
            const vel = new THREE.Vector3((Math.random()-0.5)*0.2, Math.random()*0.15, (Math.random()-0.5)*0.15);
            s.scene.add(pMesh);
            s.resultParticles.push({ mesh:pMesh, vel });
          }
          if(s.net.geometry.attributes.position) {
            const pos = s.net.geometry.attributes.position;
            for(let i = 0; i < pos.count; i++) {
              const dx = pos.getX(i) - s.ball.position.x;
              const dy = pos.getY(i) - (s.ball.position.y - gH/2);
              const dist = Math.sqrt(dx*dx + dy*dy);
              if(dist < 2) pos.setZ(i, pos.getZ(i) - 0.4 * (1 - dist/2));
            }
            pos.needsUpdate = true;
          }
          s.camera.position.x += (Math.random()-0.5)*0.4;
          s.camera.position.y += (Math.random()-0.5)*0.3;
        } else if(isMiss) {
          for(let i = 0; i < 12; i++) {
            const pGeo = new THREE.SphereGeometry(0.04, 4, 4);
            const pMat = new THREE.MeshBasicMaterial({ color:0xff4444, transparent:true, opacity:0.6 });
            const pMesh = new THREE.Mesh(pGeo, pMat);
            pMesh.position.copy(s.ball.position);
            const vel = new THREE.Vector3((Math.random()-0.5)*0.1, Math.random()*0.08, -0.06);
            s.scene.add(pMesh);
            s.resultParticles.push({ mesh:pMesh, vel });
          }
        } else {
          for(let i = 0; i < 15; i++) {
            const pGeo = new THREE.SphereGeometry(0.04, 4, 4);
            const pMat = new THREE.MeshBasicMaterial({ color:0xfb923c, transparent:true, opacity:0.7 });
            const pMesh = new THREE.Mesh(pGeo, pMat);
            pMesh.position.copy(s.keeperGroup.position);
            pMesh.position.y += 1;
            const vel = new THREE.Vector3((Math.random()-0.5)*0.12, Math.random()*0.1, (Math.random()-0.5)*0.1);
            s.scene.add(pMesh);
            s.resultParticles.push({ mesh:pMesh, vel });
          }
        }
      }
    }

    // ── SAVE PHASE: Keeper POV — camera inside goal looking outward ──
    else if(kickState === "save_ready" || kickState === "save_countdown") {
      s.cameraMode = "save";
      s.aimLineV.visible = false;
      s.aimLineH.visible = false;
      s.dot.visible = false;
      s.keeperGroup.visible = false;
      s.povGloveGroup.visible = true;
      s.targetFOV = 70;
      s.saveChecked = false; // reset save check for new round
      s.camera.position.set(0, 1.2, -0.5);
      s.camera.lookAt(0, 1.2, 20);
      s.ball.position.set(0, 0.22, 18);
      s.ball.scale.set(1,1,1);
      s.ball.visible = kickState === "save_countdown";
      s.saveBallProgress = 0;
      s.saveBallDone = false;
      s.saveDiveDir = 0;
      s.resultShown = false;
      if(s.povGloveGroup.parent !== s.camera) {
        s.scene.remove(s.povGloveGroup);
        s.camera.add(s.povGloveGroup);
        s.povGloveGroup.visible = true;
      }
    } else if(kickState === "save_dive") {
      s.cameraMode = "save";
      s.keeperGroup.visible = false;
      s.povGloveGroup.visible = true;
      s.ball.visible = true;
      // Activate save ball flight in animation loop
      if(!s.saveBallActive) {
        s.saveBallActive = true;
        s.saveBallProgress = 0;
        s.saveBallDone = false;
        const aiZone = kickAiZone !== null ? kickAiZone : 0;
        const col = aiZone % 3;
        const row = Math.floor(aiZone / 3);
        s.saveBallTargetX = (col - 1) * 2.2;
        s.saveBallTargetY = row === 0 ? 0.6 : 1.8;
      }
    } else if(kickState === "save_result") {
      s.cameraMode = "save";
      s.keeperGroup.visible = false;
      s.povGloveGroup.visible = true;
      s.ball.visible = true;
      s.aimLineV.visible = false;
      s.aimLineH.visible = false;

      if(!s.resultShown && kickBallAnim) {
        s.resultShown = true;
        const isGoal = kickBallAnim.result === "goal";
        if(!isGoal) {
          s.ball.position.z = -0.3;
          for(let i = 0; i < 20; i++) {
            const pGeo = new THREE.SphereGeometry(0.06, 4, 4);
            const pMat = new THREE.MeshBasicMaterial({ color:0x00ff88, transparent:true, opacity:0.8 });
            const pMesh = new THREE.Mesh(pGeo, pMat);
            pMesh.position.copy(s.ball.position);
            const vel = new THREE.Vector3((Math.random()-0.5)*0.15, Math.random()*0.12, (Math.random()-0.5)*0.15);
            s.scene.add(pMesh);
            s.resultParticles.push({ mesh:pMesh, vel });
          }
        } else {
          s.ball.position.z = -3;
          for(let i = 0; i < 12; i++) {
            const pGeo = new THREE.SphereGeometry(0.05, 4, 4);
            const pMat = new THREE.MeshBasicMaterial({ color:0xff4444, transparent:true, opacity:0.7 });
            const pMesh = new THREE.Mesh(pGeo, pMat);
            pMesh.position.set(s.ball.position.x, s.ball.position.y, -1);
            const vel = new THREE.Vector3((Math.random()-0.5)*0.1, Math.random()*0.08, -0.1);
            s.scene.add(pMesh);
            s.resultParticles.push({ mesh:pMesh, vel });
          }
          s.camera.position.x += (Math.random()-0.5)*0.4;
        }
      }
    }
  }, [kickState, kickPower, kickCharging, fk2X, fk2Y, kickBallAnim, isFK3Mode, kickAiZone]);

  // ── FK3: Set ball target when entering flight ──
  useEffect(() => {
    const s = threeSceneRef.current;
    if(!s) return;
    const isFK3Now = isFK3Mode || isFK3Ref.current;
    if(!isFK3Now || kickState !== "flight") return;

    // Set target from fk2X and fk2Y
    const xNorm = (fk2X / 100 - 0.5) * s.gW;
    const yNorm = (fk2Y / 100) * s.gH;
    s.ballTarget = new THREE.Vector3(xNorm, Math.max(0.22, yNorm), -0.3);
    s.ballStart = new THREE.Vector3(0, 0.22, 11);
    s.ball.position.set(0, 0.22, 11);
    s.ball.scale.set(1,1,1);
    s.flightProgress = 0;
    s.flightDone = false;
    s.keeperDiving = false;
    s.resultShown = false;
    // Reset camera to behind-ball view
    s.camera.position.set(0, 1.5, 12);
    s.targetFOV = 60;
    // Detach POV gloves from camera if attached
    if(s.povGloveGroup.parent === s.camera) {
      s.camera.remove(s.povGloveGroup);
      s.scene.add(s.povGloveGroup);
    }
    s.povGloveGroup.visible = false;
    // Reset keeper
    s.keeperGroup.visible = true;
    s.keeperGroup.position.set(0, 0, 0.5);
    s.keeperGroup.rotation.z = 0;
    s.keeperGroup.children[4].rotation.z = Math.PI/6;
    s.keeperGroup.children[5].rotation.z = -Math.PI/6;
    s.keeperGroup.children[6].position.set(-0.65, 1.5, 0);
    s.keeperGroup.children[7].position.set(0.65, 1.5, 0);
  }, [kickState, isFK3Mode]);

  // Bot chat
  useEffect(() => {
    const i=setInterval(()=>{
      const bot=CHAT_BOTS[Math.floor(Math.random()*CHAT_BOTS.length)];
      const msg=CHAT_MSGS[Math.floor(Math.random()*CHAT_MSGS.length)];
      const colors=[C.pink,C.cyan,C.gold,C.purple,C.orange,C.green];
      setChatMessages(p=>[...p.slice(-20),{u:bot,m:msg,c:colors[Math.floor(Math.random()*colors.length)],t:Date.now()}]);
    }, 4000+Math.random()*3000);
    return()=>clearInterval(i);
  }, []);

  // Tournament filling
  useEffect(() => {
    const i=setInterval(()=>{
      setTournaments(ts=>ts.map(t=>({...t,current:Math.min(t.max,t.current+(Math.random()>0.6?1:0))})));
    },5000);
    return()=>clearInterval(i);
  },[]);

  // Floating reactions
  useEffect(() => {
    const i=setInterval(()=>{
      if(Math.random()>0.4) {
        const emojis=["🔥","⚽","🏆","💪","😎","🎉","💀","👏","🤯","⭐"];
        setFloatingReactions(p=>[...p.slice(-8),{
          id:Date.now(), emoji:emojis[Math.floor(Math.random()*emojis.length)],
          x:10+Math.random()*80, dur:3+Math.random()*3,
        }]);
      }
    },2000);
    return()=>clearInterval(i);
  },[]);

  // Auto-scroll chat
  useEffect(()=>{ if(chatRef.current) chatRef.current.scrollTop=chatRef.current.scrollHeight; },[chatMessages]);

  // ── ACTIONS ──
  const notify = useCallback((msg,color=C.cyan) => { setNotif({msg,color}); setTimeout(()=>setNotif(null),2200); }, []);
  const sendChat = useCallback((msg) => { const t=msg||chatInput.trim(); if(!t) return; setChatMessages(p=>[...p.slice(-20),{u:"Steve",m:t,c:C.cyan,t:Date.now(),isYou:true}]); setChatInput(""); },[chatInput]);
  const puffLockIn = (cb) => { setPuffLocking(true); setTimeout(()=>{setPuffLocking(false);notify("✓ Locked In!",C.green);if(cb)cb();},1100); };
  const triggerInputPulse = () => { setInputPulse(true); setTimeout(()=>setInputPulse(false),600); };

  const resolveInputForGame = (game, callback) => {
    // Use already-selected device input from Arena home, skip the prompt
    if(sessionInput) { callback(sessionInput); return; }
    // Fallback: default to "puff" if no input selected
    callback("puff");
  };
  const handleAskPick = (id) => { setSessionInput(id); setShowAskPrompt(null); triggerInputPulse(); if(window._inputCb){window._inputCb(id);window._inputCb=null;} };

  // ── Preload arena images + loading screen ──
  useEffect(() => {
    let loaded = 0;
    const total = Object.values(ARENA_IMAGES).length;
    Object.values(ARENA_IMAGES).forEach(src => {
      const img = new Image();
      img.onload = img.onerror = () => { loaded++; if (loaded >= total) setTimeout(() => setArenaLoading(false), 1200); };
      img.src = src;
    });
    // Fallback: dismiss after 2.5s even if images haven't loaded
    const fallback = setTimeout(() => setArenaLoading(false), 2500);
    return () => clearTimeout(fallback);
  }, []);

  // ── Walk transition between views ──
  const walkTo = useCallback((target) => {
    if (walking || arenaView === target) return;
    setWalkFrom(arenaView);
    setWalking(true);
    setTimeout(() => {
      setArenaView(target);
      setTimeout(() => { setWalking(false); setWalkFrom(null); }, 50);
    }, 400);
  }, [walking, arenaView]);

  const walkBack = useCallback(() => { walkTo("hub"); }, [walkTo]);

  const startMatch = (game, mode) => {
    resolveInputForGame(game, (input) => {
      setMatchmaking({game,mode,stage:"searching",input});
      setTimeout(()=>{
        setMatchmaking(p=>p?{...p,stage:"found",opp:mode==="ai"?"🤖 AI Bot":mode==="random"?"🎲 Player_847":"👫 Minh"}:null);
        setTimeout(()=>{setMatchmaking(null);setGameActive({...game,activeInput:input});if(game.id==="wildwest")startDuel();if(game.id==="finalkick"||game.id==="finalkick2"||game.id==="finalkick3"){startKick(game.id);startMatchIntro(kickOpponent.current);}if(game.id==="balloon")startBalloonPop();if(game.id==="russian")startRussianRoulette();if(game.id==="puffpong")startPuffPong();if(game.id==="rhythm")startRhythmPuff();if(game.id==="tugofwar")startTugOfWar();if(game.id==="hotpotato")startHotPotato();if(game.id==="hooked")startHooked();if(game.id==="rps")startRps();if(game.id==="survivaltrivia")startSurvivalTrivia();if(game.id==="puffclock")startPuffClock();if(game.id==="beatdrop")startBeatDrop();if(game.id==="pufflimbo")startPuffLimbo();if(game.id==="puffderby")startPuffDerby();if(game.id==="higherlower")startHigherLower();},800);
      },mode==="ai"?400:1200);
    });
  };

  // ── Wild West Duel — Full Game Engine ──
  const startDuel = () => {
    // Pick random opponent
    const opp = DUEL_OPPONENTS[Math.floor(Math.random()*DUEL_OPPONENTS.length)];
    duelOpponentRef.current = opp;
    setDuelOpponent(opp);
    setDuelRound(0);
    setDuelScore({you:0, ai:0});
    setDuelRoundResults([]);
    setDuelResult(null);
    setDuelFiredShot(false);
    setDuelPuffing(false);
    setDuelPuffMeter(0);
    setDuelPuffBonus(null);
    setDuelMuzzleFlash(null);
    setDuelStaredownStage(0);
    setDuelStaredownText("");
    // Start intro sequence
    setDuelPhase("intro");
    setDuelIntroStage("enter");
    setDuelIntroCount(3);
    playFx("crowd");
    setCommentary("The duelists approach... " + opp.emoji);
    setTimeout(()=>{
      setDuelIntroStage("stats");
      setCommentary("Check the stats! Who's the fastest gun?");
    },1200);
    setTimeout(()=>{
      setDuelIntroStage("countdown");
      setDuelIntroCount(3);
      playFx("whistle");
      setCommentary("HIGH NOON approaches...");
    },2400);
    setTimeout(()=>setDuelIntroCount(2),3100);
    setTimeout(()=>setDuelIntroCount(1),3800);
    setTimeout(()=>{
      setDuelIntroStage("go");
      setCommentary("DUEL! May the fastest draw win!");
      triggerFlash("goal"); playFx("crowd");
    },4500);
    setTimeout(()=>{
      setDuelIntroStage(null);
      startDuelRound(0);
    },5200);
  };

  const startDuelRound = (roundNum) => {
    randomizeUniversalSweetSpot(); // Universal puff bar: new sweet spot each round
    setDuelFiredShot(false);
    setDuelResult(null);
    setDuelPuffing(false);
    setDuelPuffMeter(0);
    setDuelPuffBonus(null);
    setDuelMuzzleFlash(null);
    setDuelStaredownStage(0);
    setDuelStaredownText("");
    duelDrawTime.current = null;
    duelReactionTime.current = null;
    setDuelTumbleweed(Math.random() > 0.5);
    setDuelDustParticles(Array.from({length:8},(_,i)=>({id:Date.now()+i, x:Math.random()*100, y:55+Math.random()*35, size:2+Math.random()*5, dur:3+Math.random()*4})));

    // PHASE 1: Dramatic 3...2...1 countdown
    setDuelPhase("countdown");
    setDuelCountdown(3);
    playFx("tap");
    setCommentary("Round " + (roundNum+1) + "... Get ready!");

    setTimeout(()=>{ setDuelCountdown(2); playFx("tap"); },900);
    setTimeout(()=>{ setDuelCountdown(1); playFx("select"); setCommentary("Here it comes..."); },1800);
    setTimeout(()=>{
      setDuelCountdown("DRAW!");
      playFx("whistle");
      triggerFlash("save");
    },2700);

    // PHASE 2: Staredown with building tension (random 1.5-4.5s)
    setTimeout(()=>{
      setDuelCountdown(null);
      setDuelPhase("staredown");
      setDuelStaredownStage(0);
      // Round-by-round tension escalation
      const roundTension = [
        ["Eyes locked... fingers twitching...","The desert wind howls...","You can hear a pin drop...","Sweat drips... who draws first?"],
        ["The saloon goes SILENT...","Both hands hover over holsters...","A bead of sweat rolls down...","The clock ticks louder..."],
        ["MAXIMUM TENSION... Round 3!","The crowd holds their breath...","This could decide EVERYTHING...","Hearts are POUNDING..."],
        ["CHAMPIONSHIP ROUND VIBES...","The air is ELECTRIC...","One shot to seal the deal...","History in the making..."],
        ["FINAL SHOWDOWN ENERGY...","THE ENTIRE ARENA IS SILENT...","Everything rides on THIS draw...","LEGENDARY moment incoming..."],
      ];
      setCommentary(pick(roundTension[Math.min(roundNum, 4)]));

      // Build tension stages — longer staredown in later rounds
      const tensionBase = 1500 + Math.random() * 3000 + roundNum * 400; // gets longer each round
      const stage1 = tensionBase * 0.3;
      const stage2 = tensionBase * 0.6;
      const stage3 = tensionBase * 0.85;

      const stage1Texts = [
        ["The tension is THICK...","Not a soul moves...","Tumbleweeds hold their breath..."],
        ["Fingers are TWITCHING...","The crowd leans in...","A hawk circles overhead..."],
        ["You can hear your own HEARTBEAT...","The sun beats down mercilessly...","Neither blinks..."],
        ["The tension could CUT GLASS...","Time itself has STOPPED...","The desert holds its breath..."],
        ["THIS IS IT... the moment of truth...","Legends are born in moments like THIS...","The air is THICK with destiny..."],
      ];
      const stage2Texts = [
        ["WHO WILL DRAW FIRST?","The air crackles with tension...","One twitch and it is over..."],
        ["SOMEONE HAS TO MOVE...","The silence is DEAFENING...","Every nerve is on FIRE..."],
        ["The WORLD is watching...","This staredown is LEGENDARY...","Who has the NERVE?"],
        ["PURE. RAW. TENSION.","The ground beneath TREMBLES...","Even the wind STOPPED..."],
        ["THE ULTIMATE SHOWDOWN...","History will remember THIS moment...","DRAW OR DIE..."],
      ];
      duelTimerRef.current = setTimeout(()=>{
        setDuelStaredownStage(1);
        setDuelStaredownText(pick(stage1Texts[Math.min(roundNum, 4)]));
      }, stage1);

      duelSteadyTimerRef.current = setTimeout(()=>{
        setDuelStaredownStage(2);
        setDuelStaredownText(pick(stage2Texts[Math.min(roundNum, 4)]));
      }, stage2);

      const stage3Timer = setTimeout(()=>{
        setDuelStaredownStage(3);
        setDuelStaredownText("...");
      }, stage3);

      // PHASE 3: DRAW! (puff to shoot)
      duelTimerRef.current = setTimeout(()=>{
        setDuelPhase("draw");
        duelDrawTime.current = Date.now();
        triggerShake();
        triggerFlash("miss");
        playFx("whistle");
        setCommentary("DRAW! HOLD TO PUFF!");
        setDuelStaredownText("");

        // Auto-timeout after 3s if no puff
        duelTimerRef.current = setTimeout(()=>{
          if(duelDrawTime.current) {
            const aiSpeed = getAiDrawSpeed(roundNum);
            const timeoutResult = {win:false, you:3000, ai:aiSpeed, timeout:true, puffDur:0, bonus:null, bonusCoins:0};
            setDuelResult(timeoutResult);
            setDuelPhase("result");
            duelDrawTime.current = null;
            setDuelFiredShot(true);
            setDuelMuzzleFlash("right");
            setTimeout(()=>setDuelMuzzleFlash(null),500);
            playFx("lose");
            setCommentary(pick(["Too slow, partner! AI drew ages ago!","You froze up! Tumbleweed is faster!","Asleep at high noon!"]));
            handleDuelRoundEnd(false, false, timeoutResult);
          }
        }, 3000);
      }, tensionBase);
    }, 3200); // After 3..2..1..DRAW! countdown
  };

  const getAiDrawSpeed = (round) => {
    const opp = duelOpponentRef.current || DUEL_OPPONENTS[0];
    // AI gets faster each round: base speed - (round * 30-50ms)
    const base = opp.speed;
    const speedup = round * (30 + Math.random()*20);
    const jitter = (Math.random()-0.5) * 80;
    return Math.max(180, Math.floor(base - speedup + jitter));
  };

  // duelShoot = START of puff hold (mousedown/touchstart)
  const duelShoot = () => {
    if(duelFiredShot) return;

    // FOUL: puffed before DRAW phase
    if(duelPhase === "staredown" || duelPhase === "countdown") {
      setDuelFiredShot(true);
      clearTimeout(duelTimerRef.current);
      clearTimeout(duelSteadyTimerRef.current);
      duelDrawTime.current = null;
      const foulResult = {foul:true, bonusCoins:0};
      setDuelResult(foulResult);
      setDuelPhase("result");
      playFx("error");
      triggerShake();
      setDuelStats(s=>({...s, fouls:s.fouls+1}));
      setCommentary(pick(["FOUL! Jumped the gun!","Shot before DRAW! Automatic loss!","Trigger happy much?","Easy there cowboy! Too early!"]));
      notify("FOUL! Drew too early!", C.red);
      handleDuelRoundEnd(false, true, foulResult);
      return;
    }

    // Valid shot during DRAW phase: START puff hold
    if(duelPhase === "draw" && duelDrawTime.current) {
      const reactionMs = Date.now() - duelDrawTime.current;
      duelReactionTime.current = reactionMs;
      clearTimeout(duelTimerRef.current);
      setDuelPhase("puffing");
      setDuelPuffing(true);
      setDuelPuffMeter(0);
      duelPuffStart.current = Date.now();
      playFx("charge");
      // Update puff meter every 50ms
      duelPuffInterval.current = setInterval(()=>{
        const elapsed = (Date.now() - duelPuffStart.current) / 1000;
        const meter = Math.min(100, elapsed / 4.5 * 100); // 4.5s = full
        setDuelPuffMeter(meter);
        if(Math.random()<0.3) spawnPuffBubble();
        // Auto-release at 5s (blinker)
        if(elapsed >= 5.0) {
          duelReleasePuff();
        }
      }, 50);
    }
  };

  // duelReleasePuff = END of puff hold (mouseup/touchend)
  const duelReleasePuff = () => {
    if(!duelPuffing) return;
    setDuelPuffing(false);
    setDuelFiredShot(true);
    if(duelPuffInterval.current){ clearInterval(duelPuffInterval.current); duelPuffInterval.current=null; }
    duelDrawTime.current = null;

    const reactionMs = duelReactionTime.current || 999;
    const puffDuration = duelPuffStart.current ? (Date.now() - duelPuffStart.current) / 1000 : 0;
    const aiTime = getAiDrawSpeed(duelRound);
    const win = reactionMs < aiTime;

    // Determine puff bonus tier
    let bonus = "basic"; // tap < 0.5s
    let bonusCoins = 0;
    let bonusLabel = "Basic Shot";
    if(puffDuration >= 4.5) { bonus="legendary"; bonusCoins=50; bonusLabel="LEGENDARY DRAW"; }
    else if(puffDuration >= 2.0) { bonus="power"; bonusCoins=25; bonusLabel="Power Shot"; }
    else if(puffDuration >= 0.8) { bonus="quick"; bonusCoins=10; bonusLabel="Quick Draw"; }
    setDuelPuffBonus(bonus);

    const result = {win, you:reactionMs, ai:aiTime, puffDur:puffDuration, bonus, bonusCoins, bonusLabel};
    setDuelResult(result);
    setDuelPhase("result");

    // Muzzle flash
    if(win) { setDuelMuzzleFlash("left"); } else { setDuelMuzzleFlash("right"); }
    setTimeout(()=>setDuelMuzzleFlash(null),600);

    // Update stats
    setDuelStats(s=>{
      const times = [...s.drawTimes, reactionMs];
      return { ...s, fastestDraw:Math.min(s.fastestDraw,reactionMs), avgDraw:Math.round(times.reduce((a,b)=>a+b,0)/times.length), drawTimes:times };
    });

    if(win) {
      playFx("win"); playFx("crowd");
      triggerFlash("goal");
      spawnSmoke(12);
      if(bonusCoins > 0) setCoins(c=>c+bonusCoins);
      if(reactionMs < 200) {
        setCommentary("LIGHTNING! " + reactionMs + "ms! " + bonusLabel + (bonusCoins>0?" +"+bonusCoins:"") + " INHUMAN!");
        spawnConfetti(50, [C.gold, C.orange, "#fff"]);
      } else if(reactionMs < 300) {
        setCommentary("QUICK DRAW! " + reactionMs + "ms! " + bonusLabel + (bonusCoins>0?" +"+bonusCoins:""));
        spawnConfetti(25, [C.gold, C.orange]);
      } else {
        setCommentary("Got em! " + reactionMs + "ms beats " + aiTime + "ms! " + bonusLabel);
      }
      if(bonus==="legendary") {
        setCommentary("LEGENDARY DRAW! " + reactionMs + "ms + BLINKER PUFF! +50 coins! Lungs of steel!");
        spawnConfetti(60, [C.gold, C.orange, "#fff", C.green, C.pink]);
      }
      notify("Round won! " + reactionMs + "ms" + (bonusCoins>0?" +"+bonusCoins:""), C.green);
    } else {
      playFx("lose");
      triggerFlash("miss");
      spawnSmoke(8);
      const roasts = [
        aiTime+"ms vs your "+reactionMs+"ms! Outdrawn!",
        (duelOpponentRef.current||{}).name+" drew first! "+aiTime+"ms!",
        "Not quick enough partner! "+aiTime+"ms beats "+reactionMs+"ms!",
        "AI literally had time for coffee! "+reactionMs+"ms!",
        "My grandma draws faster! "+reactionMs+"ms!",
      ];
      setCommentary(pick(roasts));
      notify("AI drew faster! " + aiTime + "ms", C.red);
    }
    handleDuelRoundEnd(win, false, result);
  };

  const handleDuelRoundEnd = (win, wasFoul, resultOverride) => {
    const rr = resultOverride || duelResult || {};
    const newResults = [...duelRoundResults, {win, foul:wasFoul, you:rr.you||0, ai:rr.ai||0, bonus:rr.bonus||null, bonusCoins:rr.bonusCoins||0, puffDur:rr.puffDur||0}];
    setDuelRoundResults(newResults);
    const newScore = {...duelScore};
    if(win) newScore.you++; else newScore.ai++;
    setDuelScore(newScore);

    // Check if match is over (best of 5 = first to 3)
    setTimeout(()=>{
      if(newScore.you >= 3 || newScore.ai >= 3) {
        setDuelPhase("final");
        const matchWin = newScore.you >= 3;
        // Total bonus coins from all rounds
        const totalBonus = newResults.reduce((s,r)=>s+(r.win?r.bonusCoins:0),0);
        if(matchWin) {
          playFx("win"); playFx("crowd");
          spawnConfetti(60, [C.gold, C.orange, "#fff", C.green]);
          setCoins(c=>c+150+totalBonus);
          setDuelStats(s=>({...s, wins:s.wins+1, streak:s.streak+1}));
          setCommentary(pick(["FASTEST GUN IN THE WEST! +"+(150+totalBonus)+" coins!","CHAMPION DUELIST! "+(duelOpponentRef.current||{}).name+" tips their hat!","YOU ARE THE SHERIFF NOW!"]));
          notify("DUEL WON! +"+(150+totalBonus)+" coins!", C.gold);
        } else {
          playFx("lose");
          setDuelStats(s=>({...s, streak:0}));
          setCommentary(pick([((duelOpponentRef.current||{}).name||"AI")+" wins the duel!","Outdrawn! Better luck next time partner!","The AI claims the bounty!"]));
          notify("Duel lost!", C.red);
        }
        // Handle WC tournament progression for wildwest
        if(gameActive?.wcMode) {
          const myS = newScore.you;
          const aiS = newScore.ai;
          const isKnockout = gameActive?.wcKnockout;
          const matchIdx = gameActive?.wcMatchIdx;
          setTimeout(() => {
            resetDuel(); setGameActive(null);
            if(isKnockout) wcFinishKnockoutMatch(myS, aiS);
            else wcFinishGroupMatch(matchIdx, myS, aiS);
          }, 3500);
        }
      } else {
        setDuelPhase("round_result");
        setTimeout(()=>{
          const nextRound = duelRound + 1;
          setDuelRound(nextRound);
          startDuelRound(nextRound);
        }, 2500);
      }
    }, 1800);
  };

  const resetDuel = () => {
    clearTimeout(duelTimerRef.current);
    clearTimeout(duelSteadyTimerRef.current);
    if(duelPuffInterval.current) clearInterval(duelPuffInterval.current);
    duelDrawTime.current = null;
    duelPuffStart.current = null;
    duelReactionTime.current = null;
    setDuelPhase("menu");
    setDuelRound(0);
    setDuelScore({you:0,ai:0});
    setDuelResult(null);
    setDuelRoundResults([]);
    setDuelFiredShot(false);
    setDuelIntroStage(null);
    setDuelTumbleweed(false);
    setDuelDustParticles([]);
    setDuelState(null);
    setDuelPuffing(false);
    setDuelPuffMeter(0);
    setDuelPuffBonus(null);
    setDuelCountdown(null);
    setDuelMuzzleFlash(null);
    setDuelStaredownStage(0);
    setDuelStaredownText("");
  };
  // ── Sound FX — real audio files + synthesized fallbacks ──
  const playAudio = useCallback((src, vol=0.5) => {
    if(!audioOn) return;
    try { const a = new Audio(src); a.volume = vol; a.play().catch(()=>{}); } catch(e){}
  }, [audioOn]);
  const playFx = useCallback((type) => {
    if(!audioOn) return;
    // Real audio files for key moments
    if(type==="laugh"){ playAudio("assets/arena/laugh.m4a", 0.6); return; }
    if(type==="win"){ playAudio("assets/arena/win.m4a", 0.7); return; }
    if(type==="lose"){ playAudio("assets/arena/lose.m4a", 0.6); return; }
    // Synthesized sounds for quick feedback
    try {
      const ac = new (window.AudioContext||window.webkitAudioContext)();
      const osc = ac.createOscillator();
      const gain = ac.createGain();
      osc.connect(gain); gain.connect(ac.destination);
      if(type==="kick"){osc.type="sine";osc.frequency.setValueAtTime(220,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(880,ac.currentTime+0.15);gain.gain.setValueAtTime(0.3,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+0.2);osc.start();osc.stop(ac.currentTime+0.2);}
      else if(type==="goal"){osc.type="square";osc.frequency.setValueAtTime(523,ac.currentTime);osc.frequency.setValueAtTime(659,ac.currentTime+0.1);osc.frequency.setValueAtTime(784,ac.currentTime+0.2);gain.gain.setValueAtTime(0.2,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+0.4);osc.start();osc.stop(ac.currentTime+0.4);}
      else if(type==="save"){osc.type="sawtooth";osc.frequency.setValueAtTime(300,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(100,ac.currentTime+0.3);gain.gain.setValueAtTime(0.15,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+0.3);osc.start();osc.stop(ac.currentTime+0.3);}
      else if(type==="whistle"){osc.type="sine";osc.frequency.setValueAtTime(2800,ac.currentTime);osc.frequency.setValueAtTime(3200,ac.currentTime+0.15);osc.frequency.setValueAtTime(2800,ac.currentTime+0.3);gain.gain.setValueAtTime(0.12,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+0.5);osc.start();osc.stop(ac.currentTime+0.5);}
      else if(type==="crowd"){const n=ac.createBufferSource();const b=ac.createBuffer(1,ac.sampleRate*0.6,ac.sampleRate);const d=b.getChannelData(0);for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*0.15*Math.sin(i/d.length*Math.PI);n.buffer=b;const g2=ac.createGain();g2.gain.setValueAtTime(0.3,ac.currentTime);g2.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+0.6);n.connect(g2);g2.connect(ac.destination);n.start();}
      else if(type==="charge"){osc.type="sine";osc.frequency.setValueAtTime(200,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(1200,ac.currentTime+1.5);gain.gain.setValueAtTime(0.08,ac.currentTime);gain.gain.setValueAtTime(0.08,ac.currentTime+1.4);gain.gain.exponentialRampToValueAtTime(0.01,ac.currentTime+1.5);osc.start();osc.stop(ac.currentTime+1.5);}
      // ── UI tap sounds ──
      else if(type==="tap"){osc.type="sine";osc.frequency.setValueAtTime(800,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(600,ac.currentTime+0.06);gain.gain.setValueAtTime(0.08,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.08);osc.start();osc.stop(ac.currentTime+0.08);}
      else if(type==="select"){osc.type="sine";osc.frequency.setValueAtTime(600,ac.currentTime);osc.frequency.setValueAtTime(900,ac.currentTime+0.05);gain.gain.setValueAtTime(0.1,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.12);osc.start();osc.stop(ac.currentTime+0.12);}
      else if(type==="nav"){osc.type="sine";osc.frequency.setValueAtTime(440,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(660,ac.currentTime+0.08);gain.gain.setValueAtTime(0.06,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.1);osc.start();osc.stop(ac.currentTime+0.1);}
      else if(type==="back"){osc.type="sine";osc.frequency.setValueAtTime(660,ac.currentTime);osc.frequency.exponentialRampToValueAtTime(330,ac.currentTime+0.1);gain.gain.setValueAtTime(0.06,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.12);osc.start();osc.stop(ac.currentTime+0.12);}
      else if(type==="success"){osc.type="sine";osc.frequency.setValueAtTime(523,ac.currentTime);osc.frequency.setValueAtTime(659,ac.currentTime+0.08);osc.frequency.setValueAtTime(784,ac.currentTime+0.16);gain.gain.setValueAtTime(0.1,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.25);osc.start();osc.stop(ac.currentTime+0.25);}
      else if(type==="error"){osc.type="square";osc.frequency.setValueAtTime(200,ac.currentTime);osc.frequency.setValueAtTime(150,ac.currentTime+0.1);gain.gain.setValueAtTime(0.06,ac.currentTime);gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.15);osc.start();osc.stop(ac.currentTime+0.15);}
    } catch(e){}
  }, [audioOn]);

  // ── Visual Effects Functions ──
  const triggerFlash = (type) => { setScreenFlash(type); setTimeout(()=>setScreenFlash(null), 400); };
  const triggerShake = () => { setScreenShake(true); setTimeout(()=>setScreenShake(false), 500); };
  const spawnConfetti = (count=30,colors=[C.cyan,C.gold,C.green,C.pink,C.orange]) => {
    const particles = Array.from({length:count},(_,i)=>({
      id:Date.now()+i, x:30+Math.random()*40, y:-5, color:colors[Math.floor(Math.random()*colors.length)],
      vx:(Math.random()-0.5)*4, vy:2+Math.random()*3, rot:Math.random()*360, size:3+Math.random()*5,
    }));
    setConfettiParticles(p=>[...p,...particles].slice(-50));
    setTimeout(()=>setConfettiParticles([]),3000);
  };
  const spawnSmoke = (count=8) => {
    const puffs = Array.from({length:count},(_,i)=>({
      id:Date.now()+i, x:20+Math.random()*60, y:70+Math.random()*20,
      size:20+Math.random()*40, dur:2+Math.random()*2,
    }));
    setSmokeParticles(p=>[...p,...puffs].slice(-20));
    setTimeout(()=>setSmokeParticles([]),4000);
  };
  const triggerPuffWave = () => { setPuffWaveActive(true); spawnSmoke(15); setTimeout(()=>setPuffWaveActive(false),3000); };
  const setCommentary = (text) => { setCommentatorText(text); };

  // ═══════════════════════════════════════════════════════════════
  // PUFF REACTIONS SYSTEM
  // ═══════════════════════════════════════════════════════════════
  const PUFF_REACTION_MAP = {
    clap:{emoji:"👏",label:"Clap",color:"#00E5FF",glow:"rgba(0,229,255,0.5)"},
    fire:{emoji:"🔥",label:"Fire",color:"#FF8C00",glow:"rgba(255,140,0,0.5)"},
    omg:{emoji:"😱",label:"OMG",color:"#C084FC",glow:"rgba(192,132,252,0.5)"},
    mindblown:{emoji:"🤯",label:"Mind Blown",color:"#FF4D8D",glow:"rgba(255,77,141,0.5)"},
    skull:{emoji:"💀",label:"INSANE",color:"#FF4444",glow:"rgba(255,68,68,0.6)"},
    wave:{emoji:"🌊",label:"Wave",color:"#60A5FA",glow:"rgba(96,165,250,0.5)"},
    love:{emoji:"❤️",label:"Love",color:"#FF69B4",glow:"rgba(255,105,180,0.5)"},
  };
  const AI_AUDIENCE_NAMES = ["PuffQueen","Fan_42","LungLord","BlowMaster","VapeGod99","BreatheBoi","PuffDaddy","WindWalker","AirBender","CloudNine","GaleForce","TornadoTed","BreezyBee","StormChaser","ZephyrZoe","CycloneCy","MistMaker","FoggyFrank","HurricaneH","DraftDave"];
  const spawnPuffReaction = useCallback((reactionKey, userName) => {
    const r = PUFF_REACTION_MAP[reactionKey];
    if (!r) return;
    const id = ++puffReactionIdRef.current;
    const sizeScale = reactionKey==="skull"?2.2:reactionKey==="mindblown"?1.8:reactionKey==="omg"?1.5:reactionKey==="fire"?1.3:1;
    const x = 10+Math.random()*80, dur = 2+Math.random()*0.5;
    setPuffReactions(p=>[...p,{id,emoji:r.emoji,label:r.label,color:r.color,glow:r.glow,x,dur,size:sizeScale,spawn:Date.now()}]);
    setPuffReactionFeed(p=>[{id,user:userName||"You",emoji:r.emoji,label:r.label,color:r.color,t:Date.now()},...p].slice(0,20));
    setPuffReactionTotal(p=>p+1);
    setTimeout(()=>setPuffReactions(p=>p.filter(pr=>pr.id!==id)),(dur+0.5)*1000);
  },[]);
  const detectPuffReaction = useCallback((duration) => {
    const now = Date.now();
    setPuffHistory(prev => {
      const updated = [...prev,{t:now,dur:duration}].filter(p=>now-p.t<5000);
      if(updated.length>=3){spawnPuffReaction("wave","You");return [];}
      if(updated.length>=2){
        const last=updated[updated.length-1],prev2=updated[updated.length-2];
        if(last.t-(prev2.t+prev2.dur*1000)<300&&last.dur<0.5&&prev2.dur<0.5){spawnPuffReaction("love","You");return [];}
      }
      if(duration<0.5) spawnPuffReaction("clap","You");
      else if(duration<1.5) spawnPuffReaction("fire","You");
      else if(duration<3) spawnPuffReaction("omg","You");
      else if(duration<4.5) spawnPuffReaction("mindblown","You");
      else spawnPuffReaction("skull","You");
      return updated;
    });
  },[spawnPuffReaction]);
  useEffect(()=>{
    if(!puffReactionMode||!gameActive) return;
    const keys=Object.keys(PUFF_REACTION_MAP);
    const weights=[0.25,0.25,0.15,0.1,0.05,0.1,0.1];
    const pickW=()=>{let r=Math.random(),c=0;for(let i=0;i<keys.length;i++){c+=weights[i];if(r<c)return keys[i];}return keys[0];};
    const iv=setInterval(()=>{
      const name=AI_AUDIENCE_NAMES[Math.floor(Math.random()*AI_AUDIENCE_NAMES.length)];
      spawnPuffReaction(pickW(),name);
    },3000+Math.random()*5000);
    return ()=>clearInterval(iv);
  },[puffReactionMode,gameActive,spawnPuffReaction]);
  const renderPuffReactionsOverlay = () => {
    if(puffReactions.length===0&&!puffReactionMode) return null;
    return (
      <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:250}}>
        {puffReactions.map(r=>(
          <div key={r.id} style={{position:"absolute",left:`${r.x}%`,bottom:"10%",fontSize:24*r.size,zIndex:251,animation:`puffReactFloat ${r.dur}s ease-out forwards`,filter:`drop-shadow(0 0 12px ${r.glow}) drop-shadow(0 0 24px ${r.glow})`}}>
            {r.emoji}
            <div style={{position:"absolute",bottom:-12,left:"50%",transform:"translateX(-50%)",fontSize:7,fontWeight:800,color:r.color,textShadow:`0 0 8px ${r.glow}`,whiteSpace:"nowrap",opacity:0.9}}>{r.label}</div>
          </div>
        ))}
        {puffReactionMode&&puffReactionTotal>0&&(
          <div style={{position:"absolute",top:60,right:8,padding:"4px 10px",borderRadius:12,...GLASS_CLEAR,fontSize:9,fontWeight:800,color:C.cyan,zIndex:252,pointerEvents:"auto"}}>
            <span style={{fontSize:11}}>💨</span> {puffReactionTotal} reactions
          </div>
        )}
      </div>
    );
  };
  const renderPuffReactionFeedTab = () => (
    <div style={{...GLASS_CARD,padding:"6px 8px",flex:1,overflowY:"auto",maxHeight:120}}>
      <div style={{fontSize:7,color:C.text3,marginBottom:4,letterSpacing:1}}>💨 PUFF REACTION FEED</div>
      {puffReactionFeed.slice(0,8).map((r,i)=>(
        <div key={r.id} style={{display:"flex",gap:4,alignItems:"center",marginBottom:3,animation:"fadeIn 0.3s ease"}}>
          <span style={{fontSize:7,fontWeight:700,color:r.color,flexShrink:0}}>{r.user}:</span>
          <span style={{fontSize:12}}>{r.emoji}</span>
          <span style={{fontSize:7,color:C.text3}}>{r.label}</span>
        </div>
      ))}
      {puffReactionFeed.length===0&&(<div style={{fontSize:8,color:C.text3,fontStyle:"italic"}}>Puff to react! Your breath pattern becomes an emoji 💨</div>)}
      <div style={{marginTop:6,padding:"4px 0",borderTop:`1px solid ${C.border}`}}>
        <div style={{fontSize:6,color:C.text3,marginBottom:3,letterSpacing:0.5}}>PUFF PATTERNS:</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:3}}>
          {[{emoji:"👏",label:"Quick tap",color:"#00E5FF"},{emoji:"🔥",label:"Short puff",color:"#FF8C00"},{emoji:"😱",label:"Medium",color:"#C084FC"},{emoji:"🤯",label:"Long",color:"#FF4D8D"},{emoji:"💀",label:"Blinker",color:"#FF4444"},{emoji:"🌊",label:"Rapid 3x",color:"#60A5FA"},{emoji:"❤️",label:"Dbl tap",color:"#FF69B4"}].map((r,i)=>(
            <span key={i} style={{fontSize:6,color:r.color,padding:"1px 4px",borderRadius:4,background:`${r.color}10`,border:`1px solid ${r.color}15`}}>{r.emoji} {r.label}</span>
          ))}
        </div>
      </div>
    </div>
  );


  // ═══════════════════════════════════════════════════════════════
  // BALLOON POP — Logic
