  const ST_DEATH_MSGS = [
    "ELIMINATED! Your brain needed more THC... or less",
    "WRONG! The grim reaper puffs on your soul",
    "DEAD! Even a goldfish would know that one",
    "ELIMINATED! Your third eye was clearly closed",
    "RIP! That answer was rougher than shake",
    "GONE! You just got trimmed from the game",
    "WRONG! Pack it up, you're done",
    "ELIMINATED! Not even a blinker could save you",
  ];

  const ST_SURVIVE_MSGS = [
    "CORRECT! You live to puff another round!",
    "RIGHT! Your cannabis IQ is showing",
    "SURVIVED! The reaper passes you by... this time",
    "CORRECT! That big brain energy though",
    "YES! Knowledge is power, and power is THC",
    "NAILED IT! You're built different",
  ];

  const startSurvivalTrivia = () => {
    const avatarList = [];
    const emojis = ["\uD83D\uDE24","\uD83D\uDE0E","\uD83E\uDD74","\uD83E\uDD29","\uD83D\uDE08","\uD83D\uDC7D","\uD83E\uDD16","\uD83D\uDC7B","\uD83D\uDC38","\uD83C\uDF1A","\uD83E\uDD8A","\uD83D\uDC80","\uD83E\uDDE0","\uD83D\uDC51","\uD83D\uDD25","\uD83D\uDCA8","\uD83C\uDF3F","\uD83C\uDF55","\uD83C\uDFAE","\uD83C\uDFB5"];
    for(let i=0;i<100;i++) avatarList.push({id:i,emoji:emojis[i%emojis.length],alive:true,name:"Player_"+(100+i)});
    avatarList[42] = {id:42,emoji:"\uD83C\uDF1F",alive:true,name:"You",isYou:true};
    setStAvatars(avatarList);
    setStPlayers(100);
    setStRound(0);
    setStStreak(0);
    setStEliminated(false);
    setStAnswer(null);
    setStCorrect(null);
    setStFinalMode(false);
    setStComment("");
    setStPhase("intro");
    playFx("crowd");
    setCommentary("100 players enter... only 1 survives!");
    setTimeout(()=>{
      setStComment("SURVIVAL TRIVIA");
      setTimeout(()=>{
        setStComment("Wrong answer = INSTANT DEATH");
        setTimeout(()=>{
          setStComment("Last one standing WINS");
          setTimeout(()=>stNextQuestion(0, 100, avatarList),1500);
        },1500);
      },1500);
    },500);
  };

  const stNextQuestion = (roundNum, playersLeft, avatars) => {
    if(playersLeft <= 1 || roundNum >= ST_QUESTIONS.length) {
      setStPhase("winner");
      setStComment("WINNER WINNER! You survived all rounds!");
      playFx("crowd");
      triggerFlash("goal");
      setCoins(c=>c+500);
      notify("SURVIVOR! +500 coins!",C.gold);
      return;
    }
    const isFinal = playersLeft <= 3;
    setStFinalMode(isFinal);
    const timerDur = isFinal ? 8 : 15;
    const q = ST_QUESTIONS[roundNum % ST_QUESTIONS.length];
    const indices = [0,1,2,3];
    for(let i=indices.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[indices[i],indices[j]]=[indices[j],indices[i]];}
    const shuffled = indices.map(i=>q.a[i]);
    const correctIdx = indices.indexOf(q.c);
    setStQuestion({text:q.q,answers:shuffled,correctIdx:correctIdx});
    setStAnswer(null);
    setStCorrect(null);
    setStRound(roundNum+1);
    setStTimer(timerDur);
    setStPhase("question");
    setStComment(isFinal ? "FINAL 3 SHOWDOWN! 8 SECONDS!" : "Round "+(roundNum+1)+" - "+playersLeft+" alive");
    setCommentary(isFinal ? "FINAL SHOWDOWN! Only "+playersLeft+" remain!" : playersLeft+" players remaining...");
    if(stageRole) showMC("round_start", {n:String(roundNum+1)});
    if(stTimerRef.current) clearInterval(stTimerRef.current);
    let t = timerDur;
    stTimerRef.current = setInterval(()=>{
      t--;
      setStTimer(t);
      if(t<=0){
        clearInterval(stTimerRef.current);
        stTimerRef.current=null;
        setStAnswer(-1);
        stRevealAnswer(roundNum, -1, correctIdx, playersLeft, avatars);
      }
    },1000);
  };

  const stSelectAnswer = (idx) => {
    if(stAnswer !== null) return;
    setStAnswer(idx);
    if(stTimerRef.current){clearInterval(stTimerRef.current);stTimerRef.current=null;}
    stRevealAnswer(stRound-1, idx, stQuestion.correctIdx, stPlayers, stAvatars);
  };

  const stRevealAnswer = (roundNum, playerAnswer, correctIdx, playersLeft, avatars) => {
    setStCorrect(correctIdx);
    setStPhase("reveal");
    const isCorrect = playerAnswer === correctIdx;
    const elimRate = Math.min(0.35, 0.10 + roundNum * 0.02);
    let newAvatars = avatars.map(a=>{
      if(!a.alive) return a;
      if(a.isYou) return {...a, alive: isCorrect};
      return {...a, alive: Math.random() > elimRate};
    });
    const aliveCount = newAvatars.filter(a=>a.alive).length;
    if(aliveCount < 2 && isCorrect) {
      let revived = 0;
      newAvatars = newAvatars.map(a=>{
        if(!a.alive && !a.isYou && revived < 2){revived++;return {...a,alive:true};}
        return a;
      });
    }
    const newAlive = newAvatars.filter(a=>a.alive).length;
    const eliminated = playersLeft - newAlive;
    setStAvatars(newAvatars);
    setStPlayers(newAlive);

    if(isCorrect) {
      setStStreak(s=>s+1);
      const msg = ST_SURVIVE_MSGS[Math.floor(Math.random()*ST_SURVIVE_MSGS.length)];
      setStComment(msg);
      playFx("goal");
      setCommentary(eliminated+" players eliminated! "+newAlive+" remain.");
      const streakBonus = (stStreak+1) >= 5 ? 50 : (stStreak+1) >= 3 ? 25 : 10;
      setCoins(c=>c+streakBonus);
      notify("Correct! +"+streakBonus+" coins",C.green);
      if(stageRole) showMC("correct", {points:String(streakBonus)});
    } else {
      setStEliminated(true);
      setStStreak(0);
      const msg = ST_DEATH_MSGS[Math.floor(Math.random()*ST_DEATH_MSGS.length)];
      setStComment(msg);
      playFx("error");
      triggerFlash("miss");
      setCommentary("YOU HAVE BEEN ELIMINATED!");
      if(stageRole) showMC("wrong");
    }

    setTimeout(()=>{
      if(!isCorrect) {
        setStPhase("eliminated");
        return;
      }
      if(newAlive <= 1) {
        setStPhase("winner");
        setStComment("YOU ARE THE LAST ONE STANDING!");
        playFx("crowd");
        triggerFlash("goal");
        setCoins(c=>c+500);
        notify("SOLE SURVIVOR! +500 coins!",C.gold);
        if(stageRole) showMC("finale");
        return;
      }
      stNextQuestion(roundNum+1, newAlive, newAvatars);
    }, 2500);
  };

  const stEndGame = () => {
    if(stTimerRef.current){clearInterval(stTimerRef.current);stTimerRef.current=null;}
    setStPhase(null);
    setGameActive(null);
    setStageRole(null);setMcVisible(false);
  };

  // ===============================================================
  // PUFF CLOCK -- Full Game Engine
  // ===============================================================
  const PC_TARGETS = [2.00, 3.50, 1.75, 4.20, 0];
  const PC_ROUND_NAMES = ["Round 1: The Warm-Up","Round 2: Getting Tricky","Round 3: Precision Mode","Round 4: THE 4.20 ROUND","Round 5: SURPRISE"];

  const PC_COMEDY = [
    "Your internal clock is vibing differently right now",
    "THC messing with your perception of time!",
    "Einstein said time is relative... he was clearly high",
    "Your brain cells are counting in slow motion",
    "That was either 2 seconds or 2 hours, who knows",
    "Time flies when you're having puffs!",
    "Your temporal lobe called in sick today",
    "Somewhere a clock is laughing at you right now",
  ];

  const startPuffClock = () => {
    setPcRound(0);
    setPcResults([]);
    setPcPuffTime(0);
    setPcHolding(false);
    setPcPerfect420(false);
    setPcComment("");
    setPcPhase("intro");
    playFx("crowd");
    setCommentary("Puff Clock! Precision is everything!");
    const names = ["CloudTimer","PrecisionPuff","4.20_King","NanoSecond","TimeWarp","ChronoBlaze","ClockMaster","TickTock420"];
    const lb = names.map((n,i)=>({name:n,emoji:SPECTATOR_EMOJIS[i%SPECTATOR_EMOJIS.length],totalError:+(Math.random()*2+0.1).toFixed(2),rank:i+1}));
    lb.sort((a,b)=>a.totalError-b.totalError);
    lb.forEach((p,i)=>p.rank=i+1);
    setPcLeaderboard(lb);

    setTimeout(()=>{
      setPcComment("Puff for EXACTLY the target time!");
      setTimeout(()=>{
        setPcComment("Closest to the target wins!");
        setTimeout(()=>pcStartRound(0),1500);
      },1500);
    },500);
  };

  const pcStartRound = (roundNum) => {
    if(roundNum >= 5) {
      pcShowFinalResults();
      return;
    }
    let target = PC_TARGETS[roundNum];
    if(target === 0) target = +(1.0 + Math.random()*3.5).toFixed(2);
    setPcTarget(target);
    setPcRound(roundNum+1);
    setPcPuffTime(0);
    setPcHolding(false);
    setPcComment(PC_ROUND_NAMES[roundNum]);
    setPcPhase("target");
    setCommentary("Target: "+target.toFixed(2)+" seconds!");
    setTimeout(()=>{
      setPcPhase("puffing");
      setPcComment("PUFF NOW! Hold for "+target.toFixed(2)+"s!");
    },3000);
  };

  const pcStartPuff = () => {
    if(pcHolding || pcPhase !== "puffing") return;
    setPcHolding(true);
    pcPuffStart.current = Date.now();
    setPcPuffTime(0);
    if(pcPuffInterval.current) clearInterval(pcPuffInterval.current);
    pcPuffInterval.current = setInterval(()=>{
      const elapsed = (Date.now() - pcPuffStart.current) / 1000;
      setPcPuffTime(elapsed);
      if(elapsed >= 6.0) pcStopPuff();
    },50);
  };

  const pcStopPuff = () => {
    if(!pcHolding) return;
    setPcHolding(false);
    if(pcPuffInterval.current){clearInterval(pcPuffInterval.current);pcPuffInterval.current=null;}
    const elapsed = +(((Date.now() - pcPuffStart.current) / 1000)).toFixed(2);
    const clampedElapsed = Math.min(elapsed, 6.0);
    setPcPuffTime(clampedElapsed);
    const error = +(Math.abs(clampedElapsed - pcTarget)).toFixed(2);
    const roundResult = {round:pcRound,target:pcTarget,actual:clampedElapsed,error:error};

    let perfect = false;
    if(pcTarget === 4.20 && error <= 0.05) {
      perfect = true;
      setPcPerfect420(true);
      setCoins(c=>c+420);
      notify("PERFECT 4.20! +420 coins!",C.gold);
      triggerFlash("goal");
      playFx("crowd");
    }

    setPcResults(prev=>[...prev,roundResult]);
    setPcPhase("reveal");

    const errorComment = error <= 0.05 ? "PERFECT! Are you a robot?!" :
      error <= 0.15 ? "SO CLOSE! Almost superhuman precision!" :
      error <= 0.30 ? "Not bad! Your internal clock is pretty solid." :
      error <= 0.50 ? "Decent! "+PC_COMEDY[Math.floor(Math.random()*PC_COMEDY.length)] :
      error <= 1.0 ? "Off by "+error.toFixed(2)+"s... "+PC_COMEDY[Math.floor(Math.random()*PC_COMEDY.length)] :
      "You puffed "+clampedElapsed.toFixed(2)+"s... target was "+pcTarget.toFixed(2)+"s. Are you even trying?!";

    setPcComment(perfect ? "4.20 PERFECTION! LEGENDARY!" : errorComment);
    setCommentary("You: "+clampedElapsed.toFixed(2)+"s | Target: "+pcTarget.toFixed(2)+"s | Error: "+error.toFixed(2)+"s");

    if(!perfect) {
      const coins = error <= 0.10 ? 100 : error <= 0.25 ? 50 : error <= 0.50 ? 25 : error <= 1.0 ? 10 : 5;
      setCoins(c=>c+coins);
      notify("+"+coins+" coins (error: "+error.toFixed(2)+"s)",error<=0.25?C.green:C.gold);
      if(stageRole) { if(error<=0.25) showMC("correct",{points:String(coins)}); else if(error>1.0) showMC("wrong"); }
    }

    setPcLeaderboard(prev=>{
      const totalErr = [...pcResults,roundResult].reduce((s,r)=>s+r.error,0);
      const updated = prev.filter(p=>p.name!=="You");
      updated.push({name:"You",emoji:"\uD83C\uDF1F",totalError:+totalErr.toFixed(2),rank:0});
      updated.sort((a,b)=>a.totalError-b.totalError);
      updated.forEach((p,i)=>p.rank=i+1);
      return updated.slice(0,10);
    });

    setTimeout(()=>pcStartRound(pcRound),3500);
  };

  const pcShowFinalResults = () => {
    setPcPhase("result");
    const totalError = pcResults.reduce((s,r)=>s+r.error,0);
    const avgError = pcResults.length > 0 ? totalError / pcResults.length : 0;
    const rank = pcLeaderboard.find(p=>p.name==="You");
    const comment = avgError <= 0.15 ? "CHRONOMASTER! Your timing is INHUMAN!" :
      avgError <= 0.30 ? "Impressive precision! Your internal clock is solid." :
      avgError <= 0.60 ? "Not bad! THC only slightly warped your time perception." :
      "Your sense of time is... unique. Very unique.";
    setPcComment(comment);
    setCommentary("Final rank: #"+(rank?rank.rank:"?")+" | Avg error: "+avgError.toFixed(2)+"s");
    playFx("crowd");
    if(rank && rank.rank <= 3) {
      triggerFlash("goal");
      setCoins(c=>c+200);
      notify("TOP 3 FINISH! +200 bonus coins!",C.gold);
    }
    if(stageRole) showMC("finale");
  };

  const pcEndGame = () => {
    if(pcPuffInterval.current){clearInterval(pcPuffInterval.current);pcPuffInterval.current=null;}
    if(pcTimerRef.current){clearInterval(pcTimerRef.current);pcTimerRef.current=null;}
    setPcPhase(null);
    setGameActive(null);
    setStageRole(null);setMcVisible(false);
  };


  // ══════════════════════════════════════════════════════
  // BEAT DROP -- Music Timing Game Engine
  // ══════════════════════════════════════════════════════
  const BD_SONGS = [
    { name: "Neon Rise", buildTime: 8000, fakeAt: null, color: "#FF69B4" },
    { name: "Phantom Drop", buildTime: 12000, fakeAt: 6000, color: "#A855F7" },
    { name: "Chaos Theory", buildTime: null, color: "#FF4D8D" },
  ];

  const bdStopAudio = () => {
    try {
      if (bdOscillator.current) { bdOscillator.current.stop(); bdOscillator.current.disconnect(); bdOscillator.current = null; }
      if (bdGainNode.current) { bdGainNode.current.disconnect(); bdGainNode.current = null; }
      if (bdAudioCtx.current) { bdAudioCtx.current.close(); bdAudioCtx.current = null; }
    } catch(e) {}
  };

  const bdPlayBuildAudio = (duration) => {
    bdStopAudio();
    try {
      const ac = new (window.AudioContext || window.webkitAudioContext)();
      bdAudioCtx.current = ac;
      const osc = ac.createOscillator();
      const gain = ac.createGain();
      osc.type = "sine";
      osc.frequency.setValueAtTime(200, ac.currentTime);
      osc.frequency.exponentialRampToValueAtTime(800, ac.currentTime + duration / 1000);
      gain.gain.setValueAtTime(0.05, ac.currentTime);
      gain.gain.linearRampToValueAtTime(0.15, ac.currentTime + duration / 1000);
      osc.connect(gain);
      gain.connect(ac.destination);
      osc.start();
      bdOscillator.current = osc;
      bdGainNode.current = gain;
    } catch(e) {}
  };

  const bdPlayDropSound = () => {
    try {
      const ac = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ac.createOscillator();
      const gain = ac.createGain();
      osc.type = "sawtooth";
      osc.frequency.setValueAtTime(100, ac.currentTime);
      osc.frequency.exponentialRampToValueAtTime(40, ac.currentTime + 0.5);
      gain.gain.setValueAtTime(0.25, ac.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ac.currentTime + 0.6);
      osc.connect(gain);
      gain.connect(ac.destination);
      osc.start();
      osc.stop(ac.currentTime + 0.6);
    } catch(e) {}
  };

  const bdCleanup = () => {
    bdStopAudio();
    if (bdBuildInterval.current) { clearInterval(bdBuildInterval.current); bdBuildInterval.current = null; }
    if (bdDropTimer.current) { clearTimeout(bdDropTimer.current); bdDropTimer.current = null; }
    if (bdHoldInterval.current) { clearInterval(bdHoldInterval.current); bdHoldInterval.current = null; }
    if (window._bdActive) { window._bdActive.v = false; window._bdActive = null; }
    setBdPhase(null);
    setGameActive(null);
    setStageRole(null);setMcVisible(false);
  };

  const startBeatDrop = () => {
    const guard = { v: true };
    window._bdActive = guard;
    setBdRound(0);
    setBdScore(0);
    setBdRoundScores([]);
    setBdPhase("intro");
    setCommentary("Welcome to BEAT DROP! Hold your puff... release ON the beat!");
    playFx("crowd");
    setTimeout(() => {
      if (!guard.v) return;
      bdStartRound(0, guard);
    }, 2000);
  };

  const bdStartRound = (roundNum, guard) => {
    if (!guard.v) return;
    const song = BD_SONGS[roundNum];
    const buildTime = song.buildTime || (5000 + Math.random() * 10000);
    setBdRound(roundNum);
    setBdBuilding(true);
    setBdDropped(false);
    setBdHolding(false);
    setBdHoldStart(0);
    setBdDropTime(0);
    setBdReleaseTime(null);
    setBdBeatIntensity(0);
    setBdRoundLabel("");
    setBdFakeDropped(false);
    setBdPhase("building");
    setCommentary("Song " + (roundNum + 1) + ": " + song.name + " -- BUILDING...");
    bdPlayBuildAudio(buildTime);
    const startT = Date.now();
    bdBuildInterval.current = setInterval(() => {
      if (!guard.v) return;
      const elapsed = Date.now() - startT;
      const progress = Math.min(elapsed / buildTime, 1);
      setBdBeatIntensity(progress);
    }, 50);
    if (song.fakeAt) {
      setTimeout(() => {
        if (!guard.v) return;
        setBdFakeDropped(true);
        triggerShake();
        setCommentary("PSYCH! That was a FAKE drop!");
        setTimeout(() => { if (guard.v) setBdFakeDropped(false); }, 800);
      }, song.fakeAt);
    }
    bdDropTimer.current = setTimeout(() => {
      if (!guard.v) return;
      if (bdBuildInterval.current) { clearInterval(bdBuildInterval.current); bdBuildInterval.current = null; }
      bdStopAudio();
      setBdBuilding(false);
      setBdDropped(true);
      setBdDropTime(Date.now());
      setBdBeatIntensity(1);
      setBdPhase("dropped");
      bdPlayDropSound();
      triggerFlash("goal");
      triggerShake();
      playFx("crowd");
      setCommentary("DROP! RELEASE NOW!");
      setTimeout(() => {
        if (!guard.v) return;
        if (!bdReleaseTime) {
          bdScoreRound(roundNum, null, Date.now(), guard);
        }
      }, 3000);
    }, buildTime);
  };

  const bdStartHold = () => {
    if (bdPhase !== "building" && bdPhase !== "dropped") return;
    if (bdHolding) return;
    setBdHolding(true);
    setBdHoldStart(Date.now());
  };

  const bdReleaseHold = () => {
    if (!bdHolding) return;
    setBdHolding(false);
    const releaseT = Date.now();
    setBdReleaseTime(releaseT);
    if (!bdDropped) {
      setBdRoundLabel("EARLY");
      setCommentary("Too soon! The beat hadn't dropped yet...");
      playFx("error");
      bdScoreRound(bdRound, releaseT, null, window._bdActive);
    } else {
      bdScoreRound(bdRound, releaseT, bdDropTime, window._bdActive);
    }
  };

  const bdScoreRound = (roundNum, releaseT, dropT, guard) => {
    if (!guard || !guard.v) return;
    let pts = 0;
    let label = "";
    const holdDuration = bdHoldStart > 0 ? (releaseT || Date.now()) - bdHoldStart : 0;
    const isBlinker = holdDuration >= 5000;
    if (!releaseT || !dropT) {
      if (!dropT && releaseT) { pts = 0; label = "EARLY -- Too soon!"; }
      else { pts = 10; label = "LATE -- The party's over bro"; }
    } else {
      const diff = Math.abs(releaseT - dropT) / 1000;
      if (diff <= 0.2) { pts = 100; label = "PERFECT -- ON THE BEAT!"; playFx("goal"); triggerFlash("goal"); spawnConfetti(40, [C.pink, C.purple, C.gold]); if(stageRole) showMC("correct",{points:"100"}); }
      else if (diff <= 0.5) { pts = 75; label = "GREAT"; playFx("success"); if(stageRole) showMC("correct",{points:"75"}); }
      else if (diff <= 1.0) { pts = 50; label = "GOOD"; playFx("select"); }
      else if (releaseT > dropT) { pts = 10; label = "LATE -- The party's over bro"; playFx("save"); if(stageRole) showMC("wrong"); }
      else { pts = 0; label = "EARLY -- Too soon!"; playFx("error"); if(stageRole) showMC("wrong"); }
    }
    if (isBlinker && pts >= 50) { pts += 50; label += " + BLINKER LEGENDARY!"; playFx("crowd"); }
    setBdRoundLabel(label);
    setBdPhase("round_result");
    setBdScore(prev => prev + pts);
    setBdRoundScores(prev => [...prev, { round: roundNum + 1, pts, label }]);
    setCommentary(label + " (+" + pts + " pts)");
    const scoreForFinal = bdScore + pts;
    setTimeout(() => {
      if (!guard.v) return;
      if (roundNum < 2) { bdStartRound(roundNum + 1, guard); }
      else {
        setBdPhase("final");
        const bonus = scoreForFinal >= 250 ? 100 : scoreForFinal >= 150 ? 50 : 20;
        setCoins(c => c + bonus);
        setCommentary("BEAT DROP COMPLETE! +" + bonus + " coins!");
        if (scoreForFinal >= 250) { spawnConfetti(60, [C.pink, C.purple, C.gold, C.cyan]); playFx("win"); }
        else playFx("success");
        if(stageRole) showMC("finale");
      }
    }, 2500);
  };

  // ══════════════════════════════════════════════════════
  // PUFF LIMBO -- Endurance Challenge Game Engine
  // ══════════════════════════════════════════════════════
  const PL_TARGETS = [3.0, 3.5, 4.0, 4.2, 4.5, 4.7, 5.0];
  const PL_NAMES = ["CloudChaser99","BlinkerBetty","THC_Tony","VapeLord69","DabQueen","PuffDaddy_Jr","SmokeRing_Steve","HazeDaze","KushKing","FogMachine","MistWalker","NebulaNick","GreenGoblin","SkyHighSam","TokeToken","LitLenny","BubbleBoi","RipTide","SeshGremlin","GlassHouse"];

  const plCleanup = () => {
    if (plPuffInterval.current) { clearInterval(plPuffInterval.current); plPuffInterval.current = null; }
    if (window._plActive) { window._plActive.v = false; window._plActive = null; }
    setPlPhase(null);
    setGameActive(null);
    setStageRole(null);setMcVisible(false);
  };

  const startPuffLimbo = () => {
    const guard = { v: true };
    window._plActive = guard;
    setPlRound(0);
    setPlTarget(PL_TARGETS[0]);
    setPlPlayers(20);
    setPlSurvived(true);
    setPlPuffTime(0);
    setPlHolding(false);
    setPlEliminatedList([]);
    setPlRoundResults([]);
    setPlPhase("intro");
    setCommentary("Welcome to PUFF LIMBO! Can you survive the blinker threshold?");
    playFx("crowd");
    setTimeout(() => {
      if (!guard.v) return;
      plStartRound(0, 20, guard);
    }, 2500);
  };

  const plStartRound = (roundNum, players, guard) => {
    if (!guard.v) return;
    const target = PL_TARGETS[roundNum];
    setPlRound(roundNum);
    setPlTarget(target);
    setPlPuffTime(0);
    setPlHolding(false);
    setPlSurvived(true);
    setPlPhase("ready");
    const dangerMsg = target >= 4.5 ? " -- you can feel the blinker calling your name" : target >= 4.0 ? " -- getting serious now" : "";
    setCommentary("Round " + (roundNum + 1) + ": Hold for " + target.toFixed(1) + "s" + dangerMsg);
    if (target >= 4.5) playFx("charge");
  };

  const plStartPuff = () => {
    if (plPhase !== "ready") return;
    if (plHolding) return;
    setPlHolding(true);
    setPlPuffTime(0);
    plHoldStart.current = Date.now();
    setPlPhase("puffing");
    plPuffInterval.current = setInterval(() => {
      const elapsed = (Date.now() - plHoldStart.current) / 1000;
      setPlPuffTime(elapsed);
      if (elapsed >= 6.0) { plReleasePuff(); }
    }, 50);
  };

  const plReleasePuff = () => {
    if (!plHolding && plPhase !== "puffing") return;
    if (plPuffInterval.current) { clearInterval(plPuffInterval.current); plPuffInterval.current = null; }
    setPlHolding(false);
    const elapsed = (Date.now() - plHoldStart.current) / 1000;
    setPlPuffTime(elapsed);
    const guard = window._plActive;
    if (!guard || !guard.v) return;
    const target = PL_TARGETS[plRound];
    const survived = elapsed >= target;
    const isBlinker = elapsed >= 5.0;
    let eliminatedCount = 0;
    const failChance = target >= 4.5 ? 0.5 : target >= 4.0 ? 0.35 : 0.2;
    const currentPlayers = plPlayers;
    for (let i = 0; i < currentPlayers - 1; i++) { if (Math.random() < failChance) eliminatedCount++; }
    const newPlayers = Math.max(1, currentPlayers - eliminatedCount - (survived ? 0 : 1));
    const newEliminated = [];
    for (let i = 0; i < eliminatedCount; i++) { newEliminated.push(PL_NAMES[Math.floor(Math.random() * PL_NAMES.length)]); }
    setPlPlayers(survived ? newPlayers + 1 : newPlayers);
    if (!survived) {
      setPlSurvived(false);
      setPlPhase("eliminated");
      setCommentary("ELIMINATED at " + elapsed.toFixed(2) + "s! Needed " + target.toFixed(1) + "s");
      playFx("error");
      triggerShake();
      if(stageRole) showMC("wrong");
    } else {
      setPlSurvived(true);
      setPlPhase("result");
      setPlEliminatedList(prev => [...prev, ...newEliminated]);
      setPlRoundResults(prev => [...prev, { round: plRound + 1, target, time: elapsed, survived: true }]);
      if (isBlinker) {
        setCommentary("BLINKER HOLD! " + elapsed.toFixed(2) + "s -- ABSOLUTE LEGEND!");
        playFx("goal"); triggerFlash("goal"); spawnConfetti(50, [C.orange, C.red, C.gold]);
        if(stageRole) showMC("correct",{points:"BLINKER"});
      } else {
        setCommentary("SURVIVED! " + elapsed.toFixed(2) + "s (needed " + target.toFixed(1) + "s)");
        playFx("success");
        if(stageRole) showMC("correct",{points:String(plRound*20)});
      }
      if (eliminatedCount > 0) {
        setTimeout(() => { if (!guard.v) return; setCommentary(eliminatedCount + " players eliminated! " + (newPlayers + 1) + " remain"); }, 1500);
      }
    }
    setTimeout(() => {
      if (!guard.v) return;
      if (!survived) {
        const bonus = plRound >= 5 ? 60 : plRound >= 3 ? 30 : 10;
        setCoins(c => c + bonus);
        setPlPhase("final");
        setCommentary("Puff Limbo over! Made it to round " + (plRound + 1) + " -- +" + bonus + " coins");
        playFx(plRound >= 3 ? "success" : "save");
      } else if (plRound >= 6) {
        setPlPhase("champion");
        setCoins(c => c + 150);
        setCommentary("PUFF LIMBO CHAMPION! Survived the 5.0s BLINKER round! +150 coins!");
        spawnConfetti(80, [C.gold, C.orange, C.red, C.pink]);
        playFx("win");
        if(stageRole) showMC("finale");
        setTimeout(() => { if (!guard.v) return; setPlPhase("final"); }, 3000);
      } else {
        plStartRound(plRound + 1, newPlayers + 1, guard);
      }
    }, 2500);
  };

  // =====================================================================
  // SIMON PUFFS -- Full Game Engine
  // =====================================================================
  const spGetPuffType = (dur) => {
    if(dur < 1.0) return "short";
    if(dur < 2.5) return "medium";
    return "long";
  };

  const startSimonPuffs = () => {
    setSpPhase("intro");
    setSpPattern([]);
    setSpPlayerPattern([]);
    setSpRound(0);
    setSpScore(0);
    setSpResult(null);
    setSpAlive(true);
    setSpCurrentShow(-1);
    setSpShowingPattern(false);
    setSpPuffing(false);
    setSpPuffTime(0);
    setSpComment("");
    setSpIntroStep(0);
    setSpBestRound(0);
    setSpPlayersLeft(Math.floor(30+Math.random()*70));
    playFx("crowd");
    setCommentary("Welcome to Simon Puffs! Can you remember the pattern?");
    setTimeout(()=>setSpIntroStep(1),400);
    setTimeout(()=>setSpIntroStep(2),1000);
    setTimeout(()=>setSpIntroStep(3),1800);
    setTimeout(()=>{
      setSpIntroStep(4);
      playFx("whistle");
    },2600);
    setTimeout(()=>{
      spStartRound(1);
    },3400);
  };

  const spStartRound = (roundNum) => {
    const types = ["short","medium","long"];
    const prev = roundNum === 1 ? [] : spPattern;
    const newType = types[Math.floor(Math.random()*3)];
    const pattern = [...prev, {type:newType, duration:newType==="short"?0.6:newType==="medium"?1.8:3.2}];
    setSpPattern(pattern);
    setSpRound(roundNum);
    setSpPlayerPattern([]);
    setSpResult(null);
    setSpCurrentShow(-1);
    setSpShowingPattern(true);
    setSpPhase("showing");
    const joke = SP_COMEDY[Math.min(roundNum-1, SP_COMEDY.length-1)];
    setSpComment(joke);
    setCommentary("Watch the pattern! Round " + roundNum);
    playFx("select");
    let delay = 600;
    pattern.forEach((p, idx) => {
      setTimeout(() => {
        setSpCurrentShow(idx);
        playFx("crowd");
      }, delay);
      const showDur = p.type==="short"?600:p.type==="medium"?1200:2000;
      delay += showDur + 400;
      setTimeout(() => {
        setSpCurrentShow(-1);
      }, delay - 400);
    });
    setTimeout(() => {
      setSpShowingPattern(false);
      setSpCurrentShow(-1);
      setSpPhase("input");
      setCommentary("Your turn! Repeat the pattern!");
      setSpComment("Puff the pattern! " + pattern.length + " puffs to go...");
    }, delay + 200);
  };

  const spStartPuff = () => {
    if(spPhase !== "input" || spPuffing) return;
    setSpPuffing(true);
    setSpPuffTime(0);
    spPuffStart.current = Date.now();
    if(spPuffInterval.current) clearInterval(spPuffInterval.current);
    spPuffInterval.current = setInterval(() => {
      const elapsed = (Date.now() - spPuffStart.current) / 1000;
      setSpPuffTime(elapsed);
    }, 50);
  };

  const spEndPuff = () => {
    if(!spPuffing) return;
    if(spPuffInterval.current){clearInterval(spPuffInterval.current);spPuffInterval.current=null;}
    const dur = (Date.now() - spPuffStart.current) / 1000;
    setSpPuffing(false);
    setSpPuffTime(0);
    const puffType = spGetPuffType(dur);
    const newPlayerPattern = [...spPlayerPattern, {type:puffType, duration:dur}];
    setSpPlayerPattern(newPlayerPattern);
    const idx = newPlayerPattern.length - 1;
    if(spPattern[idx] && puffType === spPattern[idx].type) {
      playFx("crowd");
      if(newPlayerPattern.length === spPattern.length) {
        const roundScore = spRound * 100;
        setSpScore(s => s + roundScore);
        setSpBestRound(spRound);
        setSpResult("correct");
        setSpPhase("judging");
        triggerFlash("goal");
        setCommentary("CORRECT! Round " + spRound + " complete!");
        setSpComment("Perfect memory! +" + roundScore + " points!");
        setSpPlayersLeft(p => Math.max(1, Math.floor(p * (0.6 + Math.random()*0.2))));
        playFx("goal");
        if(stageRole) showMC("correct",{points:String(roundScore)});
        setTimeout(() => {
          if(spRound >= 10) {
            setSpPhase("final");
            setCommentary("INCREDIBLE! You completed all 10 rounds!");
            spawnConfetti(30);
          } else {
            spStartRound(spRound + 1);
          }
        }, 2200);
      } else {
        setSpComment((spPattern.length - newPlayerPattern.length) + " more to go...");
      }
    } else {
      setSpResult("wrong");
      setSpAlive(false);
      setSpPhase("eliminated");
      playFx("error");
      triggerFlash("miss");
      setScreenShake(true);
      setTimeout(()=>setScreenShake(false),400);
      const expected = spPattern[idx] ? spPattern[idx].type : "???";
      setCommentary("WRONG! You puffed " + puffType + " but needed " + expected + "!");
      setSpComment("Eliminated at Round " + spRound + "! You lasted " + spRound + " rounds.");
      if(stageRole) showMC("wrong");
    }
  };

  const spEndGame = () => {
    if(spPuffInterval.current){clearInterval(spPuffInterval.current);spPuffInterval.current=null;}
    if(spShowTimer.current){clearTimeout(spShowTimer.current);spShowTimer.current=null;}
    const earned = Math.min(500, spScore);
    if(earned > 0) { setCoins(c => c + earned); notify("+"+earned+" coins!", C.green); }
    setSpPhase(null);
    setGameActive(null);
    setStageRole(null);setMcVisible(false);
  };

  // =====================================================================
